const questionsFr: Question[] = [
  // ── Le triton (16) ──
  { q:"Combien de tons contient le triton ?", opts:["2","3","4","6"], a:1, fb:"Le triton = 3 tons (6 demi-tons). Son nom vient de là — tri-ton. En C majeur, il se forme entre F et B." },
  { q:"En C majeur, quelles notes forment le triton ?", opts:["C et G","F et B","E et A","D et A"], a:1, fb:"F (Fa, IVe degré) et B (Si, VIIe degré) sont les deux notes du triton de C majeur. Ce sont les notes constitutives de l'accord G7." },
  { q:"Pourquoi le triton est-il instable ?", opts:["Car il est très grave","Car il est à mi-chemin de l'octave — son ambiguïté acoustique crée une forte tension vers la résolution","Car il contient toujours des bémols","Car il est rare en musique"], a:1, fb:"Le triton divise l'octave en deux parties égales (6+6 demi-tons) — il est parfaitement symétrique. Cette absence de direction crée une tension qui appelle une résolution." },
  { q:"Vers quels degrés le triton résout-il naturellement ?", opts:["Vers V et VII","Vers I et III (ou leur équivalent)","Vers II et IV","Vers VI et VII"], a:1, fb:"Le triton F–B résout par demi-ton conjoint : F descend vers E (tierce de C) et B monte vers C (tonique). La résolution cible les degrés I et III." },
  { q:"Dans G7, la note F est :", opts:["La fondamentale","La tierce","La quinte","La septième"], a:3, fb:"G7 = G–B–D–F. F est la septième (mineure) de G7. C'est la moitié du triton — elle doit descendre vers E lors de la résolution." },
  { q:"Dans G7, la note B est :", opts:["La fondamentale","La tierce","La quinte","La septième"], a:1, fb:"G7 = G–B–D–F. B est la tierce de G7 — et c'est la sensible de C majeur. Elle doit monter vers C lors de la résolution." },
  { q:"Lors de la résolution G7 → C, la sensible B :", opts:["Descend vers G","Monte vers C par demi-ton","Reste sur B","Saute vers E"], a:1, fb:"B (sensible) monte obligatoirement vers C (tonique). Ce demi-ton ascendant est la résolution de la sensible — règle absolue de l'harmonie tonale." },
  { q:"Lors de la résolution G7 → C, la septième F :", opts:["Monte vers G","Descend vers E par degré conjoint","Reste sur F","Saute vers C"], a:1, fb:"F (septième de dominante) descend vers E (tierce de C). Ce demi-ton descendant est la résolution de la septième — règle absolue." },
  { q:"Le triton de G majeur est formé par :", opts:["G et D","C et F#","B et E","A et D"], a:1, fb:"En G majeur, les IVe (C) et VIIe (F#) degrés forment le triton. C–F# = 6 demi-tons = triton." },
  { q:"Quel accord de C majeur contient les deux notes du triton (F et B) ?", opts:["C","F","G7","Am"], a:2, fb:"G7 = G–B–D–F. Il contient B (sensible) et F (7e de dominante) — le triton complet. C'est pourquoi G7 est la dominante parfaite." },
  { q:"Le triton est instable depuis combien de siècles en musique occidentale ?", opts:["Environ 100 ans","Environ 400 ans","Environ 1 000 ans","Depuis toujours"], a:1, fb:"Depuis environ 400 ans (musique baroque), le triton est au cœur de la tension harmonique de la musique tonale. L'harmonie fonctionnelle repose sur cette instabilité." },
  { q:"La résolution du triton F–B se fait par :", opts:["Deux mouvements ascendants","Deux mouvements descendants","Un mouvement ascendant (B→C) et un descendant (F→E) — mouvements contraires","Deux sauts de quinte"], a:2, fb:"B monte vers C (+½ ton) et F descend vers E (-½ ton). Ce double mouvement contraire par demi-ton est la résolution du triton — très stable car symétrique." },
  { q:"L'accord Bdim contient-il le triton de C majeur ?", opts:["Non","Oui — il contient B et F, les deux notes du triton","Il contient F mais pas B","Il contient B mais pas F"], a:1, fb:"Bdim = B–D–F. Il contient bien B (sensible) et F (sous-dominante) — le triton complet. C'est pourquoi Bdim est une alternative fonctionnelle à G7 : les deux sont dominante." },
  { q:"Le triton s'appelle aussi :", opts:["Quarte diminuée","Quinte diminuée ou quarte augmentée","Sixte mineure","Septième diminuée"], a:1, fb:"Le triton = quarte augmentée (F–B ascendant) ou quinte diminuée (B–F descendant). 6 demi-tons dans les deux cas — même intervalle, noms différents selon le sens." },
  { q:"En F majeur, quelles notes forment le triton ?", opts:["F et C","Bb et E","G et D","A et Eb"], a:1, fb:"En F majeur, IV = Bb et VII = E. Le triton de F majeur est Bb–E (6 demi-tons). L'accord de dominante de F est C7, qui contient Bb et E." },
  { q:"Pourquoi le triton est-il la clé de l'harmonie fonctionnelle ?", opts:["Car il est rare","Car sa présence ou absence définit les fonctions T, SD et D — il organise toute la tension harmonique","Car il crée des accords de 4 notes","Car il appartient uniquement à la gamme mineure"], a:1, fb:"La présence des deux notes du triton → Dominante. Une seule → Sous-dominante. Aucune → Tonique. Le triton est le 'thermostat' de la tension harmonique." },

  // ── Fonctions tonales (20) ──
  { q:"Combien de fonctions tonales principales existent ?", opts:["2","3","4","5"], a:1, fb:"Trois fonctions : Tonique (T), Sous-dominante (SD), Dominante (D). Elles organisent tous les accords selon leur rôle dans la tension/résolution." },
  { q:"La fonction Tonique est caractérisée par :", opts:["La présence du triton complet","L'absence de F et B — stabilité, résolution, repos","La présence de F seul","La présence de B seul"], a:1, fb:"La Tonique ne contient aucune des deux notes du triton (ni F ni B). Elle est stable — c'est le point de repos et de résolution. En C : I (C) et VI (Am)." },
  { q:"La fonction Sous-dominante est caractérisée par :", opts:["La présence du triton complet","La présence de F (IVe degré) mais pas de B","La présence de B mais pas de F","L'absence de F et B"], a:1, fb:"La Sous-dominante contient F (sous-dominante) mais pas B (sensible). Elle prépare la tension sans en être le sommet. En C : II (Dm) et IV (F)." },
  { q:"La fonction Dominante est caractérisée par :", opts:["L'absence de triton","La présence de F seul","La présence du triton complet (F et B)","La présence de B seul"], a:2, fb:"La Dominante contient les deux notes du triton (F et B). Elle est le sommet de la tension — elle appelle impérativement la résolution sur la Tonique. En C : V (G7) et VII (Bdim)." },
  { q:"En C majeur, quels accords ont la fonction Tonique ?", opts:["C et G","Dm et F","C et Am","G7 et Bdim"], a:2, fb:"C (I) et Am (VI) : aucun ne contient F ni B. Ce sont les deux toniques de C majeur. Am est une tonique 'douce', souvent utilisée dans les cadences rompues." },
  { q:"En C majeur, quels accords ont la fonction Dominante ?", opts:["G7 et Am","G7 et Bdim","C et Em","Dm et F"], a:1, fb:"G7 (V) et Bdim (VII) contiennent tous deux F et B — le triton complet. Ce sont les deux dominantes de C majeur." },
  { q:"En C majeur, quels accords ont la fonction Sous-dominante ?", opts:["C et Am","G7 et Bdim","Dm et F","Em et G"], a:2, fb:"Dm (II) et F (IV) contiennent F mais pas B. Ce sont les deux sous-dominantes de C majeur." },
  { q:"L'enchaînement fondamental de l'harmonie tonale est :", opts:["T → D → SD","SD → D → T","D → T → SD","T → SD → T"], a:1, fb:"SD → D → T est la 'colonne vertébrale' de l'harmonie tonale. La Sous-dominante prépare la Dominante qui résout sur la Tonique." },
  { q:"Qu'est-ce qu'une substitution diatonique ?", opts:["Un accord renversé","Remplacer un accord par un autre de même fonction dans la même gamme","Un accord emprunté d'une autre gamme","Un accord de 4 sons"], a:1, fb:"Une substitution diatonique remplace un accord par un autre de même fonction dans la même gamme. Ex : Am peut remplacer C (tous deux = Tonique en C)." },
  { q:"En C majeur, Dm peut remplacer F car :", opts:["Ils ont la même fondamentale","Ils ont tous deux la fonction Sous-dominante — ils contiennent F mais pas B","Ils ont les mêmes notes","Ils sont à la quinte l'un de l'autre"], a:1, fb:"Dm (II) et F (IV) ont tous deux la fonction Sous-dominante : ils contiennent F (IVe degré) mais pas B. Ils peuvent donc se substituer l'un à l'autre sans changer la logique fonctionnelle." },
  { q:"En C majeur, Am peut remplacer C car :", opts:["Am est plus grave","Ils ont tous deux la fonction Tonique — ni F ni B","Am est plus stable","Ils ont la même fondamentale"], a:1, fb:"Am (VI) et C (I) ont tous deux la fonction Tonique. La cadence rompue (G7 → Am au lieu de G7 → C) exploite cette substitution pour créer un effet de surprise." },
  { q:"Pourquoi Em est-il qualifié d'accord 'bâtard' ?", opts:["Car il est diminué","Car il ne contient que B (la sensible) sans F — sa fonction est ambiguë et il est rarement utilisé seul","Car il est trop aigu","Car il n'appartient pas à C majeur"], a:1, fb:"Em (III) contient B (sensible de C) mais pas F (sous-dominante). Il ne rentre donc clairement dans aucune des trois fonctions. Les compositeurs ne sont pas d'accord sur son rôle." },
  { q:"La progression I–VI–II–V–I en C est :", opts:["T–D–SD–D–T","T–T–SD–D–T","SD–D–T–D–T","T–D–T–SD–T"], a:1, fb:"C(T) – Am(T) – Dm(SD) – G(D) – C(T) = T–T–SD–D–T. Les deux toniques s'enchaînent (I et VI), puis on suit le cycle SD–D–T." },
  { q:"Pourquoi enchaîner seulement des toniques est ennuyeux ?", opts:["Car les toniques sont dissonantes","Car la musique devient trop stable sans tension — il n'y a pas de mouvement","Car les toniques sont instables","Car on ne peut pas chanter dessus"], a:1, fb:"La musique fonctionne par contraste entre tension et résolution. Seulement des toniques = trop de stabilité, aucun élan. Seulement des dominantes = trop d'inconfort. L'équilibre est essentiel." },
  { q:"La 'couleur émotionnelle' d'une progression est déterminée par :", opts:["Son tempo","La résolution — l'accord de tonique et sa couleur majeure ou mineure","Le nombre d'accords","La hauteur des notes"], a:1, fb:"En harmonie fonctionnelle, l'émotion vient de la résolution — quelle couleur arrive à la tonique. La tension (Dominante) crée l'attente, la résolution (Tonique) donne la couleur émotionnelle." },
  { q:"Pourquoi G7 → Am est une cadence rompue ?", opts:["Car G7 est mal résolu","Car l'oreille attendait C (tonique principale) mais reçoit Am — surprise harmonique","Car Am n'est pas dans C majeur","Car G7 n'est pas la dominante"], a:1, fb:"La cadence rompue trompe les attentes : G7 (dominante) devrait résoudre sur C (tonique). En allant vers Am (tonique de substitution), on crée une surprise qui prolonge la phrase." },
  { q:"En G majeur, la dominante est :", opts:["D","D7","C","A7"], a:1, fb:"En G majeur, V = D. Avec la septième : D7 (Ré–Fa#–La–Do). D7 contient le triton de G majeur (C et F#) — il résout sur G." },
  { q:"La progression Dm–G7–C est analysée comme :", opts:["T–D–SD","SD–D–T","D–T–SD","T–SD–D"], a:1, fb:"Dm = Sous-dominante (II), G7 = Dominante (V), C = Tonique (I). SD–D–T est l'enchaînement fondamental — c'est la cadence du II–V–I." },
  { q:"Quelle est la différence fonctionnelle entre G et G7 en C majeur ?", opts:["Aucune","G7 est plus instable — il contient le triton complet (F), G ne le contient pas","G est plus instable","G7 est une tonique"], a:1, fb:"G (G–B–D) contient B (sensible) mais pas F. G7 (G–B–D–F) contient les deux notes du triton. G7 est nettement plus tendu et résout plus fortement vers C." },
  { q:"En D majeur, quelles notes forment le triton (IVe et VIIe degrés) ?", opts:["D et A","G et C#","F# et B","E et A"], a:1, fb:"En D majeur, IV = G et VII = C#. G–C# = 6 demi-tons = triton. La dominante de D majeur est A7, qui contient G et C#." },

  // ── Progressions (18) ──
  { q:"Une cadence parfaite est :", opts:["IV → I","V → I avec les deux accords à l'état fondamental","V → VI","II → V"], a:1, fb:"Cadence parfaite = V → I, tous deux à l'état fondamental. C'est la cadence la plus conclusive — G7 (fondamentale) → C (fondamentale) en C majeur." },
  { q:"Une cadence imparfaite diffère de la parfaite car :", opts:["Elle utilise IV au lieu de V","Au moins un des deux accords est renversé","Elle résout sur VI","Elle est en mode mineur"], a:1, fb:"Cadence imparfaite = V → I, mais au moins un accord est renversé. La résolution est perceptible mais moins ferme qu'avec les deux accords en état fondamental." },
  { q:"Une cadence plagale est :", opts:["V → I","IV → I — douce et solennelle","II → V","V → VI"], a:1, fb:"Cadence plagale = IV → I (F → C en C majeur). Sa couleur douce et solennelle lui vaut le surnom de cadence 'Amen' — très présente dans la musique sacrée." },
  { q:"Une demi-cadence se termine sur :", opts:["I","II","IV","V — la phrase reste suspendue"], a:3, fb:"La demi-cadence se termine sur la dominante (V) sans résoudre. C'est une suspension — comme une question restée sans réponse. L'oreille attend la suite." },
  { q:"La cadence rompue V → VI crée un effet de :", opts:["Résolution forte","Surprise — l'oreille attendait I mais reçoit VI","Instabilité maximale","Conclusion définitive"], a:1, fb:"La cadence rompue déjoue les attentes — V devrait résoudre sur I, mais va sur VI à la place. L'effet de surprise permet de prolonger la phrase sans conclure." },
  { q:"Le cycle des quintes descendantes est :", opts:["I–II–III–IV–V–VI–VII","I–IV–VII–III–VI–II–V–I — chaque accord descend d'une quinte","V–IV–III–II–I","I–V–IV–I"], a:1, fb:"I–IV–VII–III–VI–II–V–I : chaque accord descend d'une quinte (ou monte d'une quarte) par rapport au précédent. Ce mouvement de quinte est le plus naturel et le plus fort de l'harmonie." },
  { q:"La technique du 'pendule' consiste à :", opts:["Alterner entre dominante et tonique uniquement","Alterner entre deux fonctions (ex : T–SD–T–SD) avant de progresser","Répéter indéfiniment le même accord","Changer de tonalité à chaque mesure"], a:1, fb:"Le pendule alterne entre deux fonctions (souvent T–SD ou T–D) créant un effet d'oscillation. Ex : C–Am–F–C–Am–F… avant une cadence finale G7–C." },
  { q:"L'extension de fonction consiste à :", opts:["Répéter un accord deux fois","Enchaîner plusieurs accords de même fonction pour la prolonger","Changer la basse d'un accord","Renverser un accord"], a:1, fb:"On peut prolonger une fonction en enchaînant plusieurs accords de même rôle. Ex : Dm–F–G7–C = SD–SD–D–T. Les deux sous-dominantes donnent plus de poids à la préparation." },
  { q:"Dans le cycle des quintes en C majeur, quel accord suit Dm ?", opts:["C","G","Am","Bdim"], a:1, fb:"I–IV–VII–III–VI–II–V–I. Dm est le IIe degré. Le suivant dans le cycle = Ve degré = G. Dm → G : la fondamentale descend d'une quinte (Ré → Sol)." },
  { q:"La progression ii–V–I (2–5–1) est fondamentale car :", opts:["Car elle utilise trois accords","Car SD → D → T en tétrades, avec des notes communes optimisant la conduite de voix","Car elle est en mineur","Car elle utilise le triton deux fois"], a:1, fb:"II–V–I = SD–D–T en version enrichie (tétrades). Les notes communes entre Dm7 et G7 (D et F) permettent une conduite de voix minimale — c'est la cadence la plus efficace de la musique tonale." },
  { q:"En C majeur, la progression Dm7 → G7 utilise combien de notes communes ?", opts:["0","1","2","4"], a:2, fb:"Dm7 = D–F–A–C. G7 = G–B–D–F. Notes communes : D et F (2 notes). Ces deux notes peuvent rester en place, et seules A–C doivent bouger vers B–G." },
  { q:"Pour passer de II à V dans un II–V–I minimal, quelles voix doivent bouger ?", opts:["Toutes les voix","Seules la fondamentale et la tierce — les deux autres restent en place","Aucune voix ne bouge","Toutes sauf la basse"], a:1, fb:"De Dm7 (D–F–A–C) vers G7 (G–B–D–F) : D reste, F reste. Seules A descend vers G et C descend vers B. Conduite de voix minimale — deux mouvements conjoints descendants." },
  { q:"La progression C–Am–F–G est fonctionnellement :", opts:["T–D–SD–D","T–T–SD–D","SD–T–D–T","D–T–SD–T"], a:1, fb:"C = T, Am = T (substitution diatonique), F = SD, G = D. T–T–SD–D — c'est le cycle harmonique de nombreuses chansons pop modernes." },
  { q:"Dans la progression G7 → C, le triton résout par :", opts:["Deux mouvements ascendants","Deux mouvements descendants","Mouvement contraire : B monte vers C (+½), F descend vers E (-½)","Deux sauts de tierce"], a:2, fb:"B (tierce de G7, sensible) monte vers C (+½ ton). F (septième de G7) descend vers E (tierce de C) (-½ ton). Ce double mouvement contraire par demi-ton est la résolution du triton." },
  { q:"Pourquoi la cadence parfaite exige-t-elle les deux accords à l'état fondamental ?", opts:["Par convention arbitraire","Les fondamentales V et I à la basse créent le signal acoustique le plus fort d'une résolution — la basse 'confirme' le mouvement harmonique","Car les renversements sont interdits","Pour faciliter la lecture"], a:1, fb:"La basse est le fondement de l'harmonie. Quand Sol (V) et Do (I) sont à la basse, le changement de fondamentale est perçu comme une résolution ferme et définitive." },
  { q:"Quelle cadence termine traditionnellement un morceau classique ?", opts:["Demi-cadence","Cadence plagale","Cadence parfaite","Cadence rompue"], a:2, fb:"La cadence parfaite (V–I, état fondamental) est la conclusion traditionnelle. Elle apporte la résolution la plus ferme et conclusive — signal clair de fin de phrase ou de pièce." },
  { q:"La progression Am–Dm–G7–C est analysée comme :", opts:["D–T–SD–T","T–SD–D–T","SD–D–T–SD","T–D–SD–T"], a:1, fb:"Am = T (VI), Dm = SD (II), G7 = D (V), C = T (I). T–SD–D–T — c'est une variation du cycle fondamental. Am comme tonique initiale est fréquent dans les progressions en mineur relatif." },
  { q:"En G majeur, le II–V–I correspond à :", opts:["Am–D–G","Am7–D7–GMaj7","Em–D–G","Bm–E7–A"], a:1, fb:"En G majeur : II = Am7, V = D7, I = GMaj7. La cadence Am7–D7–GMaj7 est le II–V–I de G majeur." },

  // ── Conduite de voix (20) ──
  { q:"Les quatre voix du modèle SATB sont :", opts:["Soprano, Ténor, Alto, Baryton","Soprano, Alto, Ténor, Basse","Soprano, Mezzo-soprano, Ténor, Basse","Soprano, Alto, Baryton, Basse"], a:1, fb:"SATB = Soprano (voix féminine aiguë), Alto (voix féminine grave), Ténor (voix masculine aiguë), Basse (voix masculine grave). Chaque voix a sa tessiture propre." },
  { q:"La tessiture du soprano est :", opts:["G3 à C5","C4 à G5","C3 à G4","E2 à C4"], a:1, fb:"Soprano : C4 (Do central) à G5. Alto : G3 à C5. Ténor : C3 à G4. Basse : E2 à C4. Ces tessitures garantissent le confort vocal et l'équilibre acoustique." },
  { q:"Les quintes parallèles sont interdites car :", opts:["Elles sont trop dissonantes","Elles annulent l'indépendance des voix — deux voix en quinte parallèle sonnent comme une seule","Elles créent des quintes augmentées","Elles sont impossibles à chanter"], a:1, fb:"Les quintes parallèles donnent l'illusion que deux voix ne font qu'une — elles 'collent' ensemble et perdent leur indépendance mélodique. L'écriture polyphonique exige des voix indépendantes." },
  { q:"Le mouvement contraire entre deux voix est :", opts:["Les deux voix montent ensemble","Les deux voix descendent ensemble","Une voix monte, l'autre descend — le mouvement le plus équilibré","Une voix reste immobile"], a:2, fb:"Le mouvement contraire est le plus équilibré et le plus favorable à l'indépendance des voix. Il évite naturellement les octaves et quintes parallèles et donne de la vitalité à l'écriture." },
  { q:"Le mouvement oblique est :", opts:["Les deux voix qui montent","Une voix qui reste immobile pendant que l'autre se déplace","Les deux voix qui descendent","Un saut de quinte dans les deux voix"], a:1, fb:"Le mouvement oblique : une voix tient une note (ou la répète) pendant que l'autre se déplace. Très fréquent lors des résolutions, notamment pour la sensible montante." },
  { q:"Pourquoi favorise-t-on les mouvements conjoints (secondes) ?", opts:["Car ils sont plus faciles à écrire","Car ils sont plus naturels vocalement et réduisent les risques de parallèles","Car ils créent plus de tension","Car ils sont obligatoires"], a:1, fb:"Les mouvements conjoints (par secondes) sont les plus naturels pour les voix — chantables et fluides. Ils minimisent les sauts difficiles et réduisent les risques d'octaves ou quintes parallèles." },
  { q:"La règle du doublement dans un accord à l'état fondamental est :", opts:["Doubler la tierce","Doubler la quinte","Doubler la fondamentale (sauf au VIIe degré)","Doubler la septième"], a:2, fb:"On double la fondamentale par défaut — c'est la note la plus stable. Exception : au VIIe degré (Bdim), on double la tierce (D) car B est la sensible — on ne double jamais la sensible." },
  { q:"Pourquoi ne double-t-on jamais la sensible ?", opts:["Car elle est trop aiguë","Car la doubler crée deux résolutions obligatoires vers la même note — problème d'octaves parallèles à la résolution","Car elle est trop grave","Car elle est instable et difficile à intonner"], a:1, fb:"Doubler la sensible créerait deux B qui doivent tous deux monter vers C — produisant des octaves parallèles à la résolution. C'est une faute grave en écriture à 4 voix." },
  { q:"L'espacement maximal autorisé entre soprano et alto est :", opts:["Une tierce","Une quinte","Une octave","Deux octaves"], a:2, fb:"Entre soprano–alto et entre alto–ténor : maximum une octave. Entre ténor–basse : jusqu'à deux octaves tolérées. Ces proportions maintiennent l'équilibre du spectre sonore." },
  { q:"Un croisement de voix se produit quand :", opts:["Deux voix jouent la même note","L'alto chante plus haut que le soprano (ou le ténor plus haut que l'alto, etc.)","Deux voix font un saut de quinte","La basse monte dans le registre du ténor"], a:1, fb:"Le croisement de voix : une voix inférieure dépasse une voix supérieure. Ex : l'alto (G3–C5) qui monte plus haut que le soprano actuel. Interdit en écriture stricte." },
  { q:"Un chevauchement de voix se produit quand :", opts:["Deux voix jouent la même note","Une voix dépasse la note que la voix adjacente vient de quitter","Deux voix montent ensemble","La basse est trop grave"], a:1, fb:"Le chevauchement : une voix 'coiffe' la note de la voix adjacente. Ex : l'alto monte plus haut que la note que le soprano venait de quitter. Interdit en écriture stricte." },
  { q:"Lors du passage II → V dans un II–V–I, les voix F et C (de Dm7) :", opts:["Montent vers G et D","Descendent : F reste en F (7e de G7) et C descend vers B (3e de G7)","Sautent d'une tierce","Restent immobiles"], a:1, fb:"F reste en F (la septième de G7). C descend vers B (la tierce de G7). C'est le mouvement conjoint minimal : A (5e de Dm7) descend vers G (fondamentale de G7). Deux mouvements seulement." },
  { q:"La règle 'la septième descend' signifie :", opts:["La septième de tout accord descend","La septième de dominante (F dans G7) doit descendre par degré conjoint (F→E) lors de la résolution sur la tonique","La septième d'un accord mineur descend","La septième d'un accord Maj7 descend"], a:1, fb:"La septième de dominante (F dans G7) descend conjointement vers la tierce de l'accord de résolution (E dans C). Règle absolue en écriture harmonique." },
  { q:"Dans l'écriture à 4 voix, les 'octaves directes' entre soprano et basse sont :", opts:["Autorisées dans tous les cas","Interdites en mouvement direct — tolérées si le soprano avance par degrés conjoints","Toujours obligatoires","Autorisées uniquement en mineur"], a:1, fb:"Les octaves directes (soprano et basse qui bougent dans la même direction pour former une octave) sont interdites en général. Tolerance unique : si le soprano avance par demi-ton ou ton." },
  { q:"Pourquoi les mouvements disjoints (grands intervalles) sont-ils à éviter dans les voix intérieures ?", opts:["Car ils créent des consonances","Car ils créent des risques de parallèles, sont difficiles à chanter et rompent la fluidité mélodique","Car ils sont trop courts","Car ils créent trop de dissonances"], a:1, fb:"Les sauts importants dans les voix intérieures (alto, ténor) rompent la fluidité, sont difficiles à intonner et augmentent les risques d'erreurs (parallèles, chevauchements). On réserve les grands intervalles à la basse." },
  { q:"La seconde augmentée est :", opts:["Un intervalle diatonique normal","Un intervalle à éviter dans les voix — il est difficile à chanter et sonne 'oriental'","Un intervalle de base en C majeur","Un saut de tierce"], a:1, fb:"La seconde augmentée (1,5 ton, ex : Ab–B) est difficile à intonner et à chanter. Elle apparaît naturellement dans la gamme mineure harmonique et est à éviter dans les voix mélodiques." },
  { q:"Qu'est-ce qu'une voix 'chantable' ?", opts:["Une voix très rapide","Une voix qui progresse par mouvements conjoints, reste dans la tessiture et n'a pas de saut difficile","Une voix avec beaucoup de notes","Une voix qui double le soprano"], a:1, fb:"Une voix chantable : mouvements conjoints préférés, tessiture respectée, sauts limités, résolutions logiques. L'écriture SATB doit être vocalement naturelle pour chacune des 4 voix." },
  { q:"Le principe 'minimum de mouvement = meilleure écriture' signifie :", opts:["Ne jamais bouger les voix","Utiliser les notes communes et les mouvements conjoints — ne déplacer une voix que si c'est musicalement nécessaire","Écrire le moins de notes possible","Toutes les voix restent immobiles"], a:1, fb:"Une bonne conduite de voix économise les mouvements : on conserve les notes communes entre accords et on avance par degrés conjoints. Chaque déplacement doit être justifié musicalement." },
  { q:"Dans V → I en C, quelle voix fait le plus petit déplacement ?", opts:["La basse (G → C, quarte)","L'alto (B → C, demi-ton, ou D → C, ton)","Le ténor (D → E, ton)","Toutes bougent de la même distance"], a:1, fb:"La sensible (B) monte d'un demi-ton vers C — c'est le plus petit déplacement possible (½ ton). C'est pourquoi la sensible est toujours au soprano ou à l'alto pour guider la résolution." },
  { q:"Pourquoi la basse a-t-elle plus de liberté que les voix supérieures pour les grands intervalles ?", opts:["Car la basse est toujours grave","Car la basse a un rôle structurel — elle doit parfois sauter pour poser les fondamentales des accords (G → C = quarte) tout en restant dans sa tessiture","Car elle est toujours à l'état fondamental","Car la basse n'a pas de règles"], a:1, fb:"La basse pose les fondamentales des accords — parfois très éloignées (G → C = quarte). Ce rôle structurel justifie les sauts plus grands. De plus, sa tessiture grave est naturellement plus mobile." },

  // ── Synthèse et application (18) ──
  { q:"La progression Dm7–G7–CMaj7 est :", opts:["T–D–SD","SD–D–T","D–T–SD","SD–T–D"], a:1, fb:"Dm7 = Sous-dominante (II), G7 = Dominante (V), CMaj7 = Tonique (I). SD–D–T = le II–V–I jazz — l'enchaînement fondamental en version enrichie (tétrades)." },
  { q:"En A mineur, le triton fonctionnel est formé par :", opts:["A et E","D et G#","G et D","B et F"], a:1, fb:"En A mineur harmonique, IV = D et VII = G# (sensible élevée). Le triton fonctionnel de A mineur est D–G# (6 demi-tons). La dominante est E7 qui contient D et G#." },
  { q:"La cadence plagale F → C est souvent qualifiée de cadence :", opts:["Parfaite","Rompue","Amen — douce et solennelle, caractéristique de la musique sacrée","Imparfaite"], a:2, fb:"La cadence plagale (IV → I = F → C) a une couleur douce et solennelle. Son usage constant dans les 'Amen' de la musique liturgique lui a valu ce surnom." },
  { q:"Dans la progression C–Am–F–G–C, Am joue le rôle de :", opts:["Dominante","Sous-dominante","Tonique de substitution (VI remplace I)","Accord de passage"], a:2, fb:"Am (VI) est la tonique de substitution — il remplace C comme premier accord du cycle. La progression devient T(alt)–SD–D–T, avec Am comme tonique alternative." },
  { q:"Pourquoi I6/4 (C/G, 2e renversement de I) est-il instable ?", opts:["Car il est en position fondamentale","Car la quinte (G) à la basse crée un son similaire à V — l'oreille perçoit une dominante 'déguisée'","Car il est toujours suivi de IV","Car il contient le triton"], a:1, fb:"C/G (Sol à la basse) sonne comme une dominante suspendue — G est la fondamentale de V. Le 6/4 cadentiel crée une forte attente de la vraie dominante G7." },
  { q:"L'accord I6 (C/E, 1er renversement) est utilisé pour :", opts:["Remplacer la dominante","Fluidifier la ligne de basse — E à la basse permet C → E → F (montée conjointe) au lieu de C → C → F","Renforcer la tension","Toujours avant une cadence rompue"], a:1, fb:"C/E (Mi à la basse) est le premier renversement. La basse joue E — ce qui permet des lignes de basse conjointes et mélodiques. Ex : basse C–E–F–G au lieu de C–C–F–G." },
  { q:"La progression Am–F–C–G est fonctionnellement :", opts:["T–SD–T–D","D–T–SD–T","SD–T–D–T","T–T–SD–D"], a:0, fb:"Am = T (VI), F = SD (IV), C = T (I), G = D (V). T–SD–T–D. Cette progression est en fait T–T–SD–D si on analyse Am comme substitut de I : T(Am)–SD(F)–T(C)–D(G)." },
  { q:"Dans V7 → I, si on supprime la quinte de I pour éviter les octaves, on garde :", opts:["Fondamentale et quinte","Fondamentale, tierce et fondamentale doublée (3 fondamentales)","Uniquement la tierce","Fondamentale et septième"], a:1, fb:"Dans la cadence parfaite V7 → I, on supprime souvent la quinte de I pour faciliter la conduite de voix. L'accord de tonique devient : fondamentale (x2, doublée), tierce. La quinte est supprimée ('sucrée')." },
  { q:"Pourquoi la progression SD–D–T est-elle universelle en musique tonale ?", opts:["Par convention historique arbitraire","Car elle combine les trois états de l'harmonie : préparation–tension maximale–résolution — un cycle naturel tension/résolution","Car elle utilise exactement 3 accords","Car elle est en majeur"], a:1, fb:"SD–D–T reproduit un cycle naturel : préparation de la tension (SD), sommet de la tension (D), résolution et repos (T). Ce cycle structure le discours musical depuis 400 ans." },
  { q:"En A mineur harmonique, la dominante est :", opts:["Em","E","E7","Am"], a:2, fb:"En A mineur harmonique, le VIIe degré est élevé (G#). L'accord de dominante est E7 (E–G#–B–D). G# est la sensible de A mineur — elle monte vers A à la résolution." },
  { q:"La notation 'II–V–I' en jazz correspond à :", opts:["Trois accords au hasard","Sous-dominante–Dominante–Tonique en tétrades — la cadence cadentielle fondamentale du jazz","Trois accords majeurs","Trois accords de blues"], a:1, fb:"II–V–I = Dm7–G7–CMaj7 en C. Sous-dominante (m7) → Dominante (7) → Tonique (Maj7). La cadence la plus jouée du jazz — des milliers de standards en sont basés." },
  { q:"Pour passer de G7 vers C avec une conduite de voix optimale :", opts:["Toutes les voix font un grand saut","La sensible B monte vers C, la 7e F descend vers E, G reste ou descend vers G, D reste ou descend vers C","Toutes les voix restent immobiles","La basse saute d'une octave"], a:1, fb:"B → C (+½, sensible), F → E (-½, 7e de dominante), G reste ou descend (fondamentale → fondamentale ou quinte), D → C ou E (quinte → fondamentale ou tierce). Mouvements conjoints économiques." },
  { q:"Le modèle chorale de Bach est la référence pour la conduite de voix car :", opts:["Bach a inventé toutes les règles","Ses chorals appliquent systématiquement et élégamment toutes les règles de l'écriture à 4 voix — ils sont la synthèse parfaite de la pratique harmonique baroque","Ses chorals sont très simples","Bach utilisait toujours le même accord"], a:1, fb:"Les chorals de Bach (harmonisations de mélodies luthériennes) sont le corpus de référence de l'écriture à 4 voix. Chaque voix est mélodiquement logique tout en formant des harmonies correctes." },
  { q:"La fausse relation de triton se produit quand :", opts:["On joue le triton dans la même voix","Une voix joue F et une autre voix B à deux accords successifs (ou inversement), créant une relation chromatique instable","On évite le triton","On joue deux tritons successifs"], a:1, fb:"La fausse relation de triton : une voix joue F et une autre joue B (ou vice versa) dans deux accords consécutifs, mais dans des voix différentes. Cela crée une dissonance indirecte perturbante." },
  { q:"Que signifie 'mener les voix' (voice leading) ?", opts:["Choisir les accords","Guider chaque voix d'un accord à l'autre de manière fluide, logique et vocalement naturelle","Écrire la mélodie","Choisir la tonalité"], a:1, fb:"La conduite de voix (voice leading) est l'art de faire évoluer chaque ligne mélodique (S, A, T, B) d'un accord à l'autre de manière fluide, chantable et logique." },
  { q:"Dans l'écriture à 4 voix, les 3 types de mouvements sont :", opts:["Ascendant, descendant, chromatique","Direct/parallèle, contraire, oblique","Conjoint, disjoint, sauté","Lent, rapide, immobile"], a:1, fb:"Les 3 types de mouvement entre deux voix : direct/parallèle (même direction), contraire (directions opposées), oblique (une voix immobile, l'autre bouge). Le contraire est le plus équilibré." },
  { q:"Quel accord de C majeur peut initier une progression SD–D–T avec Am comme tonique finale (cadence rompue) ?", opts:["C direct","Dm → G7 → Am (cadence rompue)","F → G7 → Am (cadence rompue)","Les deux b et c sont corrects"], a:3, fb:"La cadence rompue G7 → Am peut être précédée de Dm ou de F (les deux sous-dominantes de C). Dm → G7 → Am et F → G7 → Am sont tous deux des progressions SD–D–T(rompue) valides." },
  { q:"Pourquoi dit-on que la polyphonie est 'contrôlée' dans l'écriture harmonique ?", opts:["Car il y a peu de notes","Car chaque voix est indépendante mélodiquement mais s'inscrit dans des accords harmoniques définis — équilibre horizontal et vertical","Car on ne peut pas improviser","Car les voix se suivent toujours"], a:1, fb:"L'écriture harmonique est une 'polyphonie contrôlée' : chaque voix a sa propre logique mélodique (horizontal) mais ensemble elles forment des accords corrects (vertical). L'équilibre des deux dimensions est l'art de l'harmonie." },
];

// English translations — add when available; until then falls back to fr


const questionsEn: Question[] = [{ q:"How many tones does the tritone contain?", opts:["2","3","4","6"], a:1, fb:"The tritone = 3 tones (6 semitones). Its name comes from this — tri-tone. In C major, it forms between F and B." },
{ q:"In C major, which notes form the tritone?", opts:["C and G","F and B","E and A","D and A"], a:1, fb:"F (IV scale degree) and B (VII scale degree) are the two notes of the tritone in C major. These are the constituent notes of the G7 chord." },
{ q:"Why is the tritone unstable?", opts:["Because it is very low","Because it sits halfway through the octave — its acoustic ambiguity creates a strong pull toward resolution","Because it always contains flats","Because it is rare in music"], a:1, fb:"The tritone divides the octave into two equal parts (6+6 semitones) — it is perfectly symmetrical. This lack of direction creates a tension that calls for resolution." },
{ q:"Toward which scale degrees does the tritone naturally resolve?", opts:["Toward V and VII","Toward I and III (or their equivalent)","Toward II and IV","Toward VI and VII"], a:1, fb:"The tritone F–B resolves by stepwise semitone motion: F moves down to E (third of C) and B moves up to C (tonic). The resolution targets scale degrees I and III." },
{ q:"In G7, the note F is:", opts:["The root","The third","The fifth","The seventh"], a:3, fb:"G7 = G–B–D–F. F is the (minor) seventh of G7. It is one half of the tritone — it must descend to E upon resolution." },
{ q:"In G7, the note B is:", opts:["The root","The third","The fifth","The seventh"], a:1, fb:"G7 = G–B–D–F. B is the third of G7 — and it is the leading tone of C major. It must rise to C upon resolution." },
{ q:"During the resolution G7 → C, the leading tone B:", opts:["Descends to G","Rises to C by semitone","Stays on B","Leaps to E"], a:1, fb:"B (leading tone) must rise to C (tonic). This ascending semitone is the resolution of the leading tone — an absolute rule of tonal harmony." },
{ q:"During the resolution G7 → C, the seventh F:", opts:["Rises to G","Descends to E by step","Stays on F","Leaps to C"], a:1, fb:"F (dominant seventh) descends to E (third of C). This descending semitone is the resolution of the seventh — an absolute rule." },
{ q:"The tritone of G major is formed by:", opts:["G and D","C and F#","B and E","A and D"], a:1, fb:"In G major, the IV (C) and VII (F#) scale degrees form the tritone. C–F# = 6 semitones = tritone." },
{ q:"Which chord in C major contains both notes of the tritone (F and B)?", opts:["C","F","G7","Am"], a:2, fb:"G7 = G–B–D–F. It contains B (leading tone) and F (dominant seventh) — the complete tritone. This is why G7 is the perfect dominant." },
{ q:"For approximately how many centuries has the tritone been unstable in Western music?", opts:["About 100 years","About 400 years","About 1,000 years","Since the beginning"], a:1, fb:"For about 400 years (since Baroque music), the tritone has been at the heart of harmonic tension in tonal music. Functional harmony rests on this instability." },
{ q:"The resolution of the tritone F–B occurs through:", opts:["Two ascending motions","Two descending motions","One ascending motion (B→C) and one descending (F→E) — contrary motion","Two leaps of a fifth"], a:2, fb:"B rises to C (+½ tone) and F descends to E (-½ tone). This double contrary motion by semitone is the resolution of the tritone — very stable because it is symmetrical." },
{ q:"Does the chord Bdim contain the tritone of C major?", opts:["No","Yes — it contains B and F, the two notes of the tritone","It contains F but not B","It contains B but not F"], a:1, fb:"Bdim = B–D–F. It does contain B (leading tone) and F (subdominant) — the complete tritone. This is why Bdim is a functional alternative to G7: both serve as the dominant." },
{ q:"The tritone is also called:", opts:["Diminished fourth","Diminished fifth or augmented fourth","Minor sixth","Diminished seventh"], a:1, fb:"The tritone = augmented fourth (F–B ascending) or diminished fifth (B–F descending). 6 semitones in both cases — same interval, different names depending on direction." },
{ q:"In F major, which notes form the tritone?", opts:["F and C","Bb and E","G and D","A and Eb"], a:1, fb:"In F major, IV = Bb and VII = E. The tritone of F major is Bb–E (6 semitones). The dominant chord of F is C7, which contains Bb and E." },
{ q:"Why is the tritone the key to functional harmony?", opts:["Because it is rare","Because its presence or absence defines the functions T, SD, and D — it organizes all harmonic tension","Because it creates four-note chords","Because it belongs only to the minor scale"], a:1, fb:"Both tritone notes present → Dominant. Only one → Subdominant. Neither → Tonic. The tritone is the 'thermostat' of harmonic tension." },
{ q:"How many main tonal functions are there?", opts:["2","3","4","5"], a:1, fb:"Three functions: Tonic (T), Subdominant (SD), Dominant (D). They organize all chords according to their role in tension and resolution." },
{ q:"The Tonic function is characterized by:", opts:["The presence of the complete tritone","The absence of F and B — stability, resolution, rest","The presence of F alone","The presence of B alone"], a:1, fb:"The Tonic contains neither of the two tritone notes (neither F nor B). It is stable — it is the point of rest and resolution. In C: I (C) and VI (Am)." },
{ q:"The Subdominant function is characterized by:", opts:["The presence of the complete tritone","The presence of F (IV scale degree) but not B","The presence of B but not F","The absence of F and B"], a:1, fb:"The Subdominant contains F (subdominant) but not B (leading tone). It prepares tension without being its peak. In C: II (Dm) and IV (F)." },
{ q:"The Dominant function is characterized by:", opts:["The absence of the tritone","The presence of F alone","The presence of the complete tritone (F and B)","The presence of B alone"], a:2, fb:"The Dominant contains both tritone notes (F and B). It is the peak of tension — it imperatively calls for resolution to the Tonic. In C: V (G7) and VII (Bdim)." },
{ q:"In C major, which chords have the Tonic function?", opts:["C and G","Dm and F","C and Am","G7 and Bdim"], a:2, fb:"C (I) and Am (VI): neither contains F nor B. These are the two tonics of C major. Am is a 'gentle' tonic, often used in deceptive cadences." },
{ q:"In C major, which chords have the Dominant function?", opts:["G7 and Am","G7 and Bdim","C and Em","Dm and F"], a:1, fb:"G7 (V) and Bdim (VII) both contain F and B — the complete tritone. These are the two dominants of C major." },
{ q:"In C major, which chords have the Subdominant function?", opts:["C and Am","G7 and Bdim","Dm and F","Em and G"], a:2, fb:"Dm (II) and F (IV) contain F but not B. These are the two subdominants of C major." },
{ q:"The fundamental progression of tonal harmony is:", opts:["T → D → SD","SD → D → T","D → T → SD","T → SD → T"], a:1, fb:"SD → D → T is the 'backbone' of tonal harmony. The Subdominant prepares the Dominant, which resolves to the Tonic." },
{ q:"What is a diatonic substitution?", opts:["An inverted chord","Replacing a chord with another of the same function within the same key","A chord borrowed from another key","A four-note chord"], a:1, fb:"A diatonic substitution replaces a chord with another of the same function within the same key. Ex: Am can replace C (both = Tonic in C)." },
{ q:"In C major, Dm can replace F because:", opts:["They share the same root","They both have the Subdominant function — they contain F but not B","They have the same notes","They are a fifth apart"], a:1, fb:"Dm (II) and F (IV) both have the Subdominant function: they contain F (IV scale degree) but not B. They can therefore substitute for one another without changing the functional logic." },
{ q:"In C major, Am can replace C because:", opts:["Am is lower","They both have the Tonic function — neither F nor B","Am is more stable","They share the same root"], a:1, fb:"Am (VI) and C (I) both have the Tonic function. The deceptive cadence (G7 → Am instead of G7 → C) exploits this substitution to create a surprise effect." },
{ q:"Why is Em described as a 'bastard' chord?", opts:["Because it is diminished","Because it contains only B (the leading tone) without F — its function is ambiguous and it is rarely used on its own","Because it is too high","Because it does not belong to C major"], a:1, fb:"Em (III) contains B (leading tone of C) but not F (subdominant). It therefore does not clearly fit into any of the three functions. Composers disagree about its role." },
{ q:"The progression I–VI–II–V–I in C is:", opts:["T–D–SD–D–T","T–T–SD–D–T","SD–D–T–D–T","T–D–T–SD–T"], a:1, fb:"C(T) – Am(T) – Dm(SD) – G(D) – C(T) = T–T–SD–D–T. The two tonics chain together (I and VI), then the SD–D–T cycle follows." },
{ q:"Why is chaining only tonics together boring?", opts:["Because tonics are dissonant","Because the music becomes too stable with no tension — there is no forward motion","Because tonics are unstable","Because you cannot sing over them"], a:1, fb:"Music works through contrast between tension and resolution. Only tonics = too much stability, no momentum. Only dominants = too much discomfort. Balance is essential." },
{ q:"The 'emotional color' of a progression is determined by:", opts:["Its tempo","The resolution — the tonic chord and its major or minor color","The number of chords","The pitch of the notes"], a:1, fb:"In functional harmony, emotion comes from the resolution — what color arrives at the tonic. Tension (Dominant) creates expectation; resolution (Tonic) provides the emotional color." },
{ q:"Why is G7 → Am a deceptive cadence?", opts:["Because G7 is poorly resolved","Because the ear expected C (main tonic) but receives Am — harmonic surprise","Because Am is not in C major","Because G7 is not the dominant"], a:1, fb:"The deceptive cadence tricks expectations: G7 (dominant) should resolve to C (tonic). By moving to Am (substitute tonic) instead, a surprise is created that extends the phrase." },
{ q:"In G major, the dominant is:", opts:["D","D7","C","A7"], a:1, fb:"In G major, V = D. With the seventh: D7 (D–F#–A–C). D7 contains the tritone of G major (C and F#) — it resolves to G." },
{ q:"The progression Dm–G7–C is analyzed as:", opts:["T–D–SD","SD–D–T","D–T–SD","T–SD–D"], a:1, fb:"Dm = Subdominant (II), G7 = Dominant (V), C = Tonic (I). SD–D–T is the fundamental progression — this is the II–V–I cadence." },
{ q:"What is the functional difference between G and G7 in C major?", opts:["None","G7 is more unstable — it contains the complete tritone (F), whereas G does not","G is more unstable","G7 is a tonic"], a:1, fb:"G (G–B–D) contains B (leading tone) but not F. G7 (G–B–D–F) contains both tritone notes. G7 is noticeably more tense and resolves more strongly to C." },
{ q:"In D major, which notes form the tritone (IV and VII scale degrees)?", opts:["D and A","G and C#","F# and B","E and A"], a:1, fb:"In D major, IV = G and VII = C#. G–C# = 6 semitones = tritone. The dominant of D major is A7, which contains G and C#." },
{ q:"A perfect cadence is:", opts:["IV → I","V → I with both chords in root position","V → VI","II → V"], a:1, fb:"Perfect cadence = V → I, both in root position. It is the most conclusive cadence — G7 (root position) → C (root position) in C major." },
{ q:"An imperfect cadence differs from a perfect cadence because:", opts:["It uses IV instead of V","At least one of the two chords is inverted","It resolves to VI","It is in a minor key"], a:1, fb:"Imperfect cadence = V → I, but at least one chord is inverted. The resolution is perceptible but less firm than with both chords in root position." },
{ q:"A plagal cadence is:", opts:["V → I","IV → I — gentle and solemn","II → V","V → VI"], a:1, fb:"Plagal cadence = IV → I (F → C in C major). Its gentle and solemn color has earned it the nickname 'Amen' cadence — very common in sacred music." },
{ q:"A half cadence ends on:", opts:["I","II","IV","V — the phrase remains suspended"], a:3, fb:"The half cadence ends on the dominant (V) without resolving. It is a suspension — like a question left unanswered. The ear expects what comes next." },
{ q:"The deceptive cadence V → VI creates an effect of:", opts:["Strong resolution","Surprise — the ear expected I but receives VI","Maximum instability","Definitive conclusion"], a:1, fb:"The deceptive cadence thwarts expectations — V should resolve to I, but goes to VI instead. The surprise effect allows the phrase to be extended without concluding." },
{ q:"The descending cycle of fifths is:", opts:["I–II–III–IV–V–VI–VII","I–IV–VII–III–VI–II–V–I — each chord descends by a fifth","V–IV–III–II–I","I–V–IV–I"], a:1, fb:"I–IV–VII–III–VI–II–V–I: each chord descends by a fifth (or rises by a fourth) relative to the previous one. This motion by fifths is the most natural and strongest in harmony." },
{ q:"The 'pendulum' technique consists of:", opts:["Alternating between dominant and tonic only","Alternating between two functions (e.g., T–SD–T–SD) before progressing","Repeating the same chord indefinitely","Changing key every measure"], a:1, fb:"The pendulum alternates between two functions (often T–SD or T–D), creating an oscillating effect. Ex: C–Am–F–C–Am–F… before a final cadence G7–C." },
{ q:"Function extension consists of:", opts:["Repeating a chord twice","Chaining several chords of the same function to prolong it","Changing the bass of a chord","Inverting a chord"], a:1, fb:"A function can be prolonged by chaining several chords of the same role. Ex: Dm–F–G7–C = SD–SD–D–T. The two subdominants give more weight to the preparation." },
{ q:"In the cycle of fifths in C major, which chord follows Dm?", opts:["C","G","Am","Bdim"], a:1, fb:"I–IV–VII–III–VI–II–V–I. Dm is the II scale degree. The next in the cycle = V scale degree = G. Dm → G: the root descends by a fifth (D → G)." },
{ q:"The ii–V–I progression is fundamental because:", opts:["Because it uses three chords","Because SD → D → T in tetrads, with common tones optimizing voice leading","Because it is in a minor key","Because it uses the tritone twice"], a:1, fb:"II–V–I = SD–D–T in enriched form (tetrads). The common tones between Dm7 and G7 (D and F) allow minimal voice movement — it is the most efficient cadence in tonal music." },
{ q:"In C major, how many common tones does the progression Dm7 → G7 share?", opts:["0","1","2","4"], a:2, fb:"Dm7 = D–F–A–C. G7 = G–B–D–F. Common tones: D and F (2 notes). These two notes can remain in place, and only A–C need to move to B–G." },
{ q:"To move from II to V in a minimal II–V–I, which voices must move?", opts:["All voices","Only the root and the third — the other two remain in place","No voices move","All voices except the bass"], a:1, fb:"From Dm7 (D–F–A–C) to G7 (G–B–D–F): D stays, F stays. Only A descends to G and C descends to B. Minimal voice leading — two stepwise descending motions." },
{ q:"The progression C–Am–F–G is functionally:", opts:["T–D–SD–D","T–T–SD–D","SD–T–D–T","D–T–SD–T"], a:1, fb:"C = T, Am = T (diatonic substitution), F = SD, G = D. T–T–SD–D — this is the harmonic cycle of many modern pop songs." },
{ q:"In the progression G7 → C, the tritone resolves through:", opts:["Two ascending motions","Two descending motions","Contrary motion: B rises to C (+½), F descends to E (-½)","Two leaps of a third"], a:2, fb:"B (third of G7, leading tone) rises to C (+½ tone). F (seventh of G7) descends to E (third of C) (-½ tone). This double contrary motion by semitone is the resolution of the tritone." },
{ q:"Why does a perfect cadence require both chords in root position?", opts:["By arbitrary convention","The roots V and I in the bass create the strongest acoustic signal of a resolution — the bass 'confirms' the harmonic motion","Because inversions are forbidden","To make reading easier"], a:1, fb:"The bass is the foundation of harmony. When G (V) and C (I) are in the bass, the change of root is perceived as a firm and definitive resolution." },
{ q:"Which cadence traditionally ends a classical piece?", opts:["Half cadence","Plagal cadence","Perfect cadence","Deceptive cadence"], a:2, fb:"The perfect cadence (V–I, root position) is the traditional conclusion. It provides the firmest and most conclusive resolution — a clear signal of the end of a phrase or piece." },
{ q:"The progression Am–Dm–G7–C is analyzed as:", opts:["D–T–SD–T","T–SD–D–T","SD–D–T–SD","T–D–SD–T"], a:1, fb:"Am = T (VI), Dm = SD (II), G7 = D (V), C = T (I). T–SD–D–T — this is a variation of the fundamental cycle. Am as an opening tonic is common in progressions in the relative minor." },
{ q:"In G major, the II–V–I corresponds to:", opts:["Am–D–G","Am7–D7–GMaj7","Em–D–G","Bm–E7–A"], a:1, fb:"In G major: II = Am7, V = D7, I = GMaj7. The cadence Am7–D7–GMaj7 is the II–V–I of G major." },
{ q:"The four voices of the SATB model are:", opts:["Soprano, Tenor, Alto, Baritone","Soprano, Alto, Tenor, Bass","Soprano, Mezzo-soprano, Tenor, Bass","Soprano, Alto, Baritone, Bass"], a:1, fb:"SATB = Soprano (high female voice), Alto (low female voice), Tenor (high male voice), Bass (low male voice). Each voice has its own range." },
{ q:"The soprano range is:", opts:["G3 to C5","C4 to G5","C3 to G4","E2 to C4"], a:1, fb:"Soprano: C4 (middle C) to G5. Alto: G3 to C5. Tenor: C3 to G4. Bass: E2 to C4. These ranges ensure vocal comfort and acoustic balance." },
{ q:"Parallel fifths are forbidden because:", opts:["They are too dissonant","They cancel the independence of the voices — two voices moving in parallel fifths sound like one","They create augmented fifths","They are impossible to sing"], a:1, fb:"Parallel fifths give the impression that two voices are fused into one — they 'stick together' and lose their melodic independence. Polyphonic writing requires independent voices." },
{ q:"Contrary motion between two voices is:", opts:["Both voices moving up together","Both voices moving down together","One voice moving up while the other moves down — the most balanced motion","One voice remaining still"], a:2, fb:"Contrary motion is the most balanced and most conducive to voice independence. It naturally avoids parallel octaves and fifths, and gives vitality to the writing." },
{ q:"Oblique motion is:", opts:["Both voices moving up","One voice staying still while the other moves","Both voices moving down","A leap of a fifth in both voices"], a:1, fb:"Oblique motion: one voice holds a note (or repeats it) while the other moves. Very common during resolutions, especially for the ascending leading tone." },
{ q:"Why are stepwise motions (seconds) preferred?", opts:["Because they are easier to write","Because they are more natural vocally and reduce the risk of parallels","Because they create more tension","Because they are mandatory"], a:1, fb:"Stepwise motions (by seconds) are the most natural for voices — singable and fluid. They minimize difficult leaps and reduce the risk of parallel octaves or fifths." },
{ q:"The doubling rule for a chord in root position is:", opts:["Double the third","Double the fifth","Double the root (except at the VII scale degree)","Double the seventh"], a:2, fb:"The root is doubled by default — it is the most stable note. Exception: at the VII scale degree (Bdim), the third (D) is doubled because B is the leading tone — the leading tone is never doubled." },
{ q:"Why is the leading tone never doubled?", opts:["Because it is too high","Because doubling it creates two obligatory resolutions to the same note — leading to parallel octaves upon resolution","Because it is too low","Because it is unstable and hard to intone"], a:1, fb:"Doubling the leading tone would create two B's that must both rise to C — producing parallel octaves at the resolution. This is a serious error in four-voice writing." },
{ q:"The maximum allowed spacing between soprano and alto is:", opts:["A third","A fifth","An octave","Two octaves"], a:2, fb:"Between soprano–alto and between alto–tenor: maximum one octave. Between tenor–bass: up to two octaves is tolerated. These proportions maintain the balance of the sound spectrum." },
{ q:"A voice crossing occurs when:", opts:["Two voices play the same note","The alto sings higher than the soprano (or the tenor higher than the alto, etc.)","Two voices make a leap of a fifth","The bass rises into the tenor's range"], a:1, fb:"Voice crossing: a lower voice exceeds a higher voice. Ex: the alto (G3–C5) rising higher than the current soprano note. Forbidden in strict writing." },
{ q:"A voice overlap occurs when:", opts:["Two voices play the same note","One voice exceeds the note that the adjacent voice has just left","Two voices move up together","The bass is too low"], a:1, fb:"Voice overlap: one voice 'overtops' the note of the adjacent voice. Ex: the alto rises higher than the note the soprano just left. Forbidden in strict writing." },
{ q:"During the move from II to V in a II–V–I, the voices F and C (from Dm7):", opts:["Rise to G and D","Descend: F stays on F (7th of G7) and C descends to B (3rd of G7)","Leap by a third","Stay still"], a:1, fb:"F stays on F (the seventh of G7). C descends to B (the third of G7). This is the minimal stepwise motion: A (5th of Dm7) descends to G (root of G7). Only two movements." },
{ q:"The rule 'the seventh descends' means:", opts:["The seventh of any chord descends","The dominant seventh (F in G7) must descend by step (F→E) when resolving to the tonic","The seventh of a minor chord descends","The seventh of a Maj7 chord descends"], a:1, fb:"The dominant seventh (F in G7) descends by step to the third of the resolving chord (E in C). An absolute rule in harmonic writing." },
{ q:"In four-voice writing, 'direct octaves' between soprano and bass are:", opts:["Allowed in all cases","Forbidden in direct motion — tolerated if the soprano moves by step","Always mandatory","Allowed only in minor keys"], a:1, fb:"Direct octaves (soprano and bass moving in the same direction to form an octave) are generally forbidden. The one exception: if the soprano moves by a semitone or whole tone." },
{ q:"Why are disjunct motions (large intervals) to be avoided in the inner voices?", opts:["Because they create consonances","Because they create risks of parallels, are difficult to sing, and break melodic fluidity","Because they are too short","Because they create too much dissonance"], a:1, fb:"Large leaps in the inner voices (alto, tenor) break fluidity, are difficult to intone, and increase the risk of errors (parallels, overlaps). Large intervals are reserved for the bass." },
{ q:"The augmented second is:", opts:["A normal diatonic interval","An interval to avoid in the voices — it is difficult to sing and sounds 'oriental'","A basic interval in C major","A leap of a third"], a:1, fb:"The augmented second (1.5 tones, e.g., Ab–B) is difficult to intone and sing. It appears naturally in the harmonic minor scale and should be avoided in melodic voice lines." },
{ q:"What is a 'singable' voice?", opts:["A very fast voice","A voice that progresses by stepwise motion, stays within its range, and has no difficult leaps","A voice with many notes","A voice that doubles the soprano"], a:1, fb:"A singable voice: stepwise motion preferred, range respected, leaps limited, logical resolutions. SATB writing must be vocally natural for each of the 4 voices." },
{ q:"The principle 'minimum motion = best writing' means:", opts:["Never move the voices","Use common tones and stepwise motion — only move a voice if it is musically necessary","Write as few notes as possible","All voices remain still"], a:1, fb:"Good voice leading economizes motion: common tones between chords are retained and progression is by step. Each movement must be musically justified." },
{ q:"In V → I in C, which voice makes the smallest move?", opts:["The bass (G → C, a fourth)","The alto (B → C, a semitone, or D → C, a whole tone)","The tenor (D → E, a whole tone)","All voices move the same distance"], a:1, fb:"The leading tone (B) rises by a semitone to C — the smallest possible motion (½ tone). This is why the leading tone is always placed in the soprano or alto to guide the resolution." },
{ q:"Why does the bass have more freedom than the upper voices for large intervals?", opts:["Because the bass is always low","Because the bass has a structural role — it must sometimes leap to establish chord roots (G → C = a fourth) while remaining in its range","Because it is always in root position","Because the bass has no rules"], a:1, fb:"The bass establishes chord roots — sometimes very distant from each other (G → C = a fourth). This structural role justifies larger leaps. Moreover, its low range is naturally more mobile." },
{ q:"The progression Dm7–G7–CMaj7 is:", opts:["T–D–SD","SD–D–T","D–T–SD","SD–T–D"], a:1, fb:"Dm7 = Subdominant (II), G7 = Dominant (V), CMaj7 = Tonic (I). SD–D–T = the jazz II–V–I — the fundamental progression in enriched form (tetrads)." },
{ q:"In A minor, the functional tritone is formed by:", opts:["A and E","D and G#","G and D","B and F"], a:1, fb:"In harmonic A minor, IV = D and VII = G# (raised leading tone). The functional tritone of A minor is D–G# (6 semitones). The dominant is E7, which contains D and G#." },
{ q:"The plagal cadence F → C is often called the:", opts:["Perfect cadence","Deceptive cadence","Amen cadence — gentle and solemn, characteristic of sacred music","Imperfect cadence"], a:2, fb:"The plagal cadence (IV → I = F → C) has a gentle and solemn color. Its constant use in liturgical music 'Amens' has given it this nickname." },
{ q:"In the progression C–Am–F–G–C, Am plays the role of:", opts:["Dominant","Subdominant","Substitute tonic (VI replaces I)","Passing chord"], a:2, fb:"Am (VI) is the substitute tonic — it replaces C as the first chord of the cycle. The progression becomes T(alt)–SD–D–T, with Am as the alternative tonic." },
{ q:"Why is I6/4 (C/G, 2nd inversion of I) unstable?", opts:["Because it is in root position","Because the fifth (G) in the bass creates a sound similar to V — the ear perceives a 'disguised' dominant","Because it is always followed by IV","Because it contains the tritone"], a:1, fb:"C/G (G in the bass) sounds like a suspended dominant — G is the root of V. The cadential 6/4 creates a strong expectation of the true dominant G7." },
{ q:"The chord I6 (C/E, 1st inversion) is used to:", opts:["Replace the dominant","Smooth the bass line — E in the bass allows C → E → F (stepwise ascent) instead of C → C → F","Reinforce tension","Always precede a deceptive cadence"], a:1, fb:"C/E (E in the bass) is the first inversion. The bass plays E — enabling stepwise and melodic bass lines. Ex: bass C–E–F–G instead of C–C–F–G." },
{ q:"The progression Am–F–C–G is functionally:", opts:["T–SD–T–D","D–T–SD–T","SD–T–D–T","T–T–SD–D"], a:0, fb:"Am = T (VI), F = SD (IV), C = T (I), G = D (V). T–SD–T–D. This progression can also be analyzed as T–T–SD–D if Am is treated as a substitute for I: T(Am)–SD(F)–T(C)–D(G)." },
{ q:"In V7 → I, if the fifth of I is omitted to avoid parallel octaves, what is retained?", opts:["Root and fifth","Root, third, and doubled root (3 roots)","Only the third","Root and seventh"], a:1, fb:"To avoid parallel octaves when the leading tone B resolves to C, the fifth (G) of the tonic chord is often omitted. The tonic I retains root and third, with the root doubled: C–E–C." },
];

const questionsEs: Question[] = [{ q:"¿Cuántos tonos contiene el tritono?", opts:["2","3","4","6"], a:1, fb:"El tritono = 3 tonos (6 semitonos). Su nombre viene de ahí — tri-tono. En C mayor, se forma entre F y B." },
{ q:"En C mayor, ¿qué notas forman el tritono?", opts:["C y G","F y B","E y A","D y A"], a:1, fb:"F (Fa, IVº grado) y B (Si, VIIº grado) son las dos notas del tritono de C mayor. Son las notas constitutivas del acorde G7." },
{ q:"¿Por qué es inestable el tritono?", opts:["Porque es muy grave","Porque está a mitad de la octava — su ambigüedad acústica crea una fuerte tensión hacia la resolución","Porque siempre contiene bemoles","Porque es raro en la música"], a:1, fb:"El tritono divide la octava en dos partes iguales (6+6 semitonos) — es perfectamente simétrico. Esta ausencia de dirección crea una tensión que pide resolución." },
{ q:"¿Hacia qué grados resuelve naturalmente el tritono?", opts:["Hacia V y VII","Hacia I y III (o su equivalente)","Hacia II y IV","Hacia VI y VII"], a:1, fb:"El tritono F–B resuelve por semitono conjunto: F desciende hacia E (tercera de C) y B asciende hacia C (tónica). La resolución apunta a los grados I y III." },
{ q:"En G7, la nota F es:", opts:["La fundamental","La tercera","La quinta","La séptima"], a:3, fb:"G7 = G–B–D–F. F es la séptima (menor) de G7. Es la mitad del tritono — debe descender hacia E en la resolución." },
{ q:"En G7, la nota B es:", opts:["La fundamental","La tercera","La quinta","La séptima"], a:1, fb:"G7 = G–B–D–F. B es la tercera de G7 — y es la sensible de C mayor. Debe ascender hacia C en la resolución." },
{ q:"En la resolución G7 → C, la sensible B:", opts:["Desciende hacia G","Asciende hacia C por semitono","Permanece en B","Salta hacia E"], a:1, fb:"B (sensible) asciende obligatoriamente hacia C (tónica). Este semitono ascendente es la resolución de la sensible — regla absoluta de la armonía tonal." },
{ q:"En la resolución G7 → C, la séptima F:", opts:["Asciende hacia G","Desciende hacia E por grado conjunto","Permanece en F","Salta hacia C"], a:1, fb:"F (séptima de dominante) desciende hacia E (tercera de C). Este semitono descendente es la resolución de la séptima — regla absoluta." },
{ q:"El tritono de G mayor está formado por:", opts:["G y D","C y F#","B y E","A y D"], a:1, fb:"En G mayor, los grados IV (C) y VII (F#) forman el tritono. C–F# = 6 semitonos = tritono." },
{ q:"¿Qué acorde de C mayor contiene las dos notas del tritono (F y B)?", opts:["C","F","G7","Am"], a:2, fb:"G7 = G–B–D–F. Contiene B (sensible) y F (7ª de dominante) — el tritono completo. Por eso G7 es la dominante perfecta." },
{ q:"¿Desde hace cuántos siglos es inestable el tritono en la música occidental?", opts:["Aproximadamente 100 años","Aproximadamente 400 años","Aproximadamente 1000 años","Desde siempre"], a:1, fb:"Desde aproximadamente 400 años (música barroca), el tritono está en el centro de la tensión armónica de la música tonal. La armonía funcional se basa en esta inestabilidad." },
{ q:"La resolución del tritono F–B se produce por:", opts:["Dos movimientos ascendentes","Dos movimientos descendentes","Un movimiento ascendente (B→C) y uno descendente (F→E) — movimientos contrarios","Dos saltos de quinta"], a:2, fb:"B asciende hacia C (+½ tono) y F desciende hacia E (-½ tono). Este doble movimiento contrario por semitono es la resolución del tritono — muy estable porque es simétrico." },
{ q:"¿Contiene el acorde Bdim el tritono de C mayor?", opts:["No","Sí — contiene B y F, las dos notas del tritono","Contiene F pero no B","Contiene B pero no F"], a:1, fb:"Bdim = B–D–F. Contiene B (sensible) y F (subdominante) — el tritono completo. Por eso Bdim es una alternativa funcional a G7: ambos son dominante." },
{ q:"El tritono también se llama:", opts:["Cuarta disminuida","Quinta disminuida o cuarta aumentada","Sexta menor","Séptima disminuida"], a:1, fb:"El tritono = cuarta aumentada (F–B ascendente) o quinta disminuida (B–F descendente). 6 semitonos en ambos casos — el mismo intervalo, nombres distintos según la dirección." },
{ q:"En F mayor, ¿qué notas forman el tritono?", opts:["F y C","Bb y E","G y D","A y Eb"], a:1, fb:"En F mayor, IV = Bb y VII = E. El tritono de F mayor es Bb–E (6 semitonos). El acorde de dominante de F es C7, que contiene Bb y E." },
{ q:"¿Por qué el tritono es la clave de la armonía funcional?", opts:["Porque es raro","Porque su presencia o ausencia define las funciones T, SD y D — organiza toda la tensión armónica","Porque crea acordes de 4 notas","Porque pertenece únicamente a la escala menor"], a:1, fb:"La presencia de las dos notas del tritono → Dominante. Solo una → Subdominante. Ninguna → Tónica. El tritono es el 'termostato' de la tensión armónica." },
{ q:"¿Cuántas funciones tonales principales existen?", opts:["2","3","4","5"], a:1, fb:"Tres funciones: Tónica (T), Subdominante (SD), Dominante (D). Organizan todos los acordes según su papel en la tensión/resolución." },
{ q:"La función Tónica se caracteriza por:", opts:["La presencia del tritono completo","La ausencia de F y B — estabilidad, resolución, reposo","La presencia de F solo","La presencia de B solo"], a:1, fb:"La Tónica no contiene ninguna de las dos notas del tritono (ni F ni B). Es estable — es el punto de reposo y resolución. En C: I (C) y VI (Am)." },
{ q:"La función Subdominante se caracteriza por:", opts:["La presencia del tritono completo","La presencia de F (IVº grado) pero no de B","La presencia de B pero no de F","La ausencia de F y B"], a:1, fb:"La Subdominante contiene F (subdominante) pero no B (sensible). Prepara la tensión sin ser su punto máximo. En C: II (Dm) y IV (F)." },
{ q:"La función Dominante se caracteriza por:", opts:["La ausencia de tritono","La presencia de F solo","La presencia del tritono completo (F y B)","La presencia de B solo"], a:2, fb:"La Dominante contiene las dos notas del tritono (F y B). Es el punto máximo de tensión — exige imperiosamente la resolución sobre la Tónica. En C: V (G7) y VII (Bdim)." },
{ q:"En C mayor, ¿qué acordes tienen función Tónica?", opts:["C y G","Dm y F","C y Am","G7 y Bdim"], a:2, fb:"C (I) y Am (VI): ninguno contiene F ni B. Son las dos tónicas de C mayor. Am es una tónica 'suave', frecuentemente usada en las cadencias rotas." },
{ q:"En C mayor, ¿qué acordes tienen función Dominante?", opts:["G7 y Am","G7 y Bdim","C y Em","Dm y F"], a:1, fb:"G7 (V) y Bdim (VII) contienen ambos F y B — el tritono completo. Son las dos dominantes de C mayor." },
{ q:"En C mayor, ¿qué acordes tienen función Subdominante?", opts:["C y Am","G7 y Bdim","Dm y F","Em y G"], a:2, fb:"Dm (II) y F (IV) contienen F pero no B. Son las dos subdominantes de C mayor." },
{ q:"La progresión fundamental de la armonía tonal es:", opts:["T → D → SD","SD → D → T","D → T → SD","T → SD → T"], a:1, fb:"SD → D → T es la 'columna vertebral' de la armonía tonal. La Subdominante prepara la Dominante, que resuelve sobre la Tónica." },
{ q:"¿Qué es una sustitución diatónica?", opts:["Un acorde invertido","Reemplazar un acorde por otro de la misma función dentro de la misma escala","Un acorde tomado prestado de otra escala","Un acorde de 4 sonidos"], a:1, fb:"Una sustitución diatónica reemplaza un acorde por otro de la misma función dentro de la misma escala. Ej: Am puede reemplazar a C (ambos = Tónica en C)." },
{ q:"En C mayor, Dm puede reemplazar a F porque:", opts:["Tienen la misma fundamental","Ambos tienen función Subdominante — contienen F pero no B","Tienen las mismas notas","Están a la quinta uno del otro"], a:1, fb:"Dm (II) y F (IV) tienen ambos función Subdominante: contienen F (IVº grado) pero no B. Por tanto pueden sustituirse mutuamente sin cambiar la lógica funcional." },
{ q:"En C mayor, Am puede reemplazar a C porque:", opts:["Am es más grave","Ambos tienen función Tónica — ni F ni B","Am es más estable","Tienen la misma fundamental"], a:1, fb:"Am (VI) y C (I) tienen ambos función Tónica. La cadencia rota (G7 → Am en lugar de G7 → C) aprovecha esta sustitución para crear un efecto sorpresa." },
{ q:"¿Por qué se llama 'acorde bastardo' a Em?", opts:["Porque es disminuido","Porque solo contiene B (la sensible) sin F — su función es ambigua y rara vez se usa solo","Porque es demasiado agudo","Porque no pertenece a C mayor"], a:1, fb:"Em (III) contiene B (sensible de C) pero no F (subdominante). No encaja claramente en ninguna de las tres funciones. Los compositores no se ponen de acuerdo sobre su papel." },
{ q:"La progresión I–VI–II–V–I en C se analiza como:", opts:["T–D–SD–D–T","T–T–SD–D–T","SD–D–T–D–T","T–D–T–SD–T"], a:1, fb:"C(T) – Am(T) – Dm(SD) – G(D) – C(T) = T–T–SD–D–T. Las dos tónicas se encadenan (I y VI), luego se sigue el ciclo SD–D–T." },
{ q:"¿Por qué encadenar solo tónicas resulta aburrido?", opts:["Porque las tónicas son disonantes","Porque la música se vuelve demasiado estable sin tensión — no hay movimiento","Porque las tónicas son inestables","Porque no se puede cantar sobre ellas"], a:1, fb:"La música funciona por contraste entre tensión y resolución. Solo tónicas = demasiada estabilidad, ningún impulso. Solo dominantes = demasiada incomodidad. El equilibrio es esencial." },
{ q:"El 'color emocional' de una progresión está determinado por:", opts:["Su tempo","La resolución — el acorde de tónica y su color mayor o menor","El número de acordes","La altura de las notas"], a:1, fb:"En armonía funcional, la emoción proviene de la resolución — qué color llega a la tónica. La tensión (Dominante) crea la expectativa, la resolución (Tónica) da el color emocional." },
{ q:"¿Por qué G7 → Am es una cadencia rota?", opts:["Porque G7 está mal resuelto","Porque el oído esperaba C (tónica principal) pero recibe Am — sorpresa armónica","Porque Am no está en C mayor","Porque G7 no es la dominante"], a:1, fb:"La cadencia rota defrauda las expectativas: G7 (dominante) debería resolver sobre C (tónica). Al ir hacia Am (tónica de sustitución), se crea una sorpresa que prolonga la frase." },
{ q:"En G mayor, la dominante es:", opts:["D","D7","C","A7"], a:1, fb:"En G mayor, V = D. Con la séptima: D7 (Re–Fa#–La–Do). D7 contiene el tritono de G mayor (C y F#) — resuelve sobre G." },
{ q:"La progresión Dm–G7–C se analiza como:", opts:["T–D–SD","SD–D–T","D–T–SD","T–SD–D"], a:1, fb:"Dm = Subdominante (II), G7 = Dominante (V), C = Tónica (I). SD–D–T es el encadenamiento fundamental — es la cadencia del II–V–I." },
{ q:"¿Cuál es la diferencia funcional entre G y G7 en C mayor?", opts:["Ninguna","G7 es más inestable — contiene el tritono completo (F), G no lo contiene","G es más inestable","G7 es una tónica"], a:1, fb:"G (G–B–D) contiene B (sensible) pero no F. G7 (G–B–D–F) contiene las dos notas del tritono. G7 es notablemente más tenso y resuelve con más fuerza hacia C." },
{ q:"En D mayor, ¿qué notas forman el tritono (IVº y VIIº grados)?", opts:["D y A","G y C#","F# y B","E y A"], a:1, fb:"En D mayor, IV = G y VII = C#. G–C# = 6 semitonos = tritono. La dominante de D mayor es A7, que contiene G y C#." },
{ q:"Una cadencia perfecta es:", opts:["IV → I","V → I con los dos acordes en estado fundamental","V → VI","II → V"], a:1, fb:"Cadencia perfecta = V → I, ambos en estado fundamental. Es la cadencia más conclusiva — G7 (fundamental) → C (fundamental) en C mayor." },
{ q:"Una cadencia imperfecta se diferencia de la perfecta porque:", opts:["Usa IV en lugar de V","Al menos uno de los dos acordes está invertido","Resuelve sobre VI","Está en modo menor"], a:1, fb:"Cadencia imperfecta = V → I, pero al menos un acorde está invertido. La resolución es perceptible pero menos firme que con los dos acordes en estado fundamental." },
{ q:"Una cadencia plagal es:", opts:["V → I","IV → I — suave y solemne","II → V","V → VI"], a:1, fb:"Cadencia plagal = IV → I (F → C en C mayor). Su color suave y solemne le ha valido el apodo de cadencia 'Amén' — muy presente en la música sacra." },
{ q:"Una semicadencia termina sobre:", opts:["I","II","IV","V — la frase queda suspendida"], a:3, fb:"La semicadencia termina sobre la dominante (V) sin resolver. Es una suspensión — como una pregunta sin respuesta. El oído espera la continuación." },
{ q:"La cadencia rota V → VI crea un efecto de:", opts:["Resolución fuerte","Sorpresa — el oído esperaba I pero recibe VI","Inestabilidad máxima","Conclusión definitiva"], a:1, fb:"La cadencia rota defrauda las expectativas — V debería resolver sobre I, pero va a VI en su lugar. El efecto sorpresa permite prolongar la frase sin concluir." },
{ q:"El ciclo de quintas descendentes es:", opts:["I–II–III–IV–V–VI–VII","I–IV–VII–III–VI–II–V–I — cada acorde desciende una quinta","V–IV–III–II–I","I–V–IV–I"], a:1, fb:"I–IV–VII–III–VI–II–V–I: cada acorde desciende una quinta (o asciende una cuarta) respecto al anterior. Este movimiento de quinta es el más natural y poderoso de la armonía." },
{ q:"La técnica del 'péndulo' consiste en:", opts:["Alternar únicamente entre dominante y tónica","Alternar entre dos funciones (ej: T–SD–T–SD) antes de progresar","Repetir indefinidamente el mismo acorde","Cambiar de tonalidad en cada compás"], a:1, fb:"El péndulo alterna entre dos funciones (frecuentemente T–SD o T–D) creando un efecto de oscilación. Ej: C–Am–F–C–Am–F… antes de una cadencia final G7–C." },
{ q:"La extensión de función consiste en:", opts:["Repetir un acorde dos veces","Encadenar varios acordes de la misma función para prolongarla","Cambiar el bajo de un acorde","Invertir un acorde"], a:1, fb:"Se puede prolongar una función encadenando varios acordes del mismo papel. Ej: Dm–F–G7–C = SD–SD–D–T. Las dos subdominantes dan más peso a la preparación." },
{ q:"En el ciclo de quintas en C mayor, ¿qué acorde sigue a Dm?", opts:["C","G","Am","Bdim"], a:1, fb:"I–IV–VII–III–VI–II–V–I. Dm es el IIº grado. El siguiente en el ciclo = Vº grado = G. Dm → G: la fundamental desciende una quinta (Re → Sol)." },
{ q:"La progresión ii–V–I (2–5–1) es fundamental porque:", opts:["Porque usa tres acordes","Porque SD → D → T en tétradas, con notas comunes que optimizan la conducción de voces","Porque está en menor","Porque usa el tritono dos veces"], a:1, fb:"II–V–I = SD–D–T en versión enriquecida (tétradas). Las notas comunes entre Dm7 y G7 (D y F) permiten una conducción de voces mínima — es la cadencia más eficaz de la música tonal." },
{ q:"En C mayor, la progresión Dm7 → G7 tiene cuántas notas comunes:", opts:["0","1","2","4"], a:2, fb:"Dm7 = D–F–A–C. G7 = G–B–D–F. Notas comunes: D y F (2 notas). Estas dos notas pueden permanecer en su lugar, y solo A–C deben moverse hacia B–G." },
{ q:"Para pasar de II a V en un II–V–I mínimo, ¿qué voces deben moverse?", opts:["Todas las voces","Solo la fundamental y la tercera — las otras dos permanecen en su lugar","Ninguna voz se mueve","Todas excepto el bajo"], a:1, fb:"De Dm7 (D–F–A–C) hacia G7 (G–B–D–F): D permanece, F permanece. Solo A desciende hacia G y C desciende hacia B. Conducción de voces mínima — dos movimientos conjuntos descendentes." },
{ q:"La progresión C–Am–F–G es funcionalmente:", opts:["T–D–SD–D","T–T–SD–D","SD–T–D–T","D–T–SD–T"], a:1, fb:"C = T, Am = T (sustitución diatónica), F = SD, G = D. T–T–SD–D — es el ciclo armónico de numerosas canciones pop modernas." },
{ q:"En la progresión G7 → C, el tritono resuelve por:", opts:["Dos movimientos ascendentes","Dos movimientos descendentes","Movimiento contrario: B asciende hacia C (+½), F desciende hacia E (-½)","Dos saltos de tercera"], a:2, fb:"B (tercera de G7, sensible) asciende hacia C (+½ tono). F (séptima de G7) desciende hacia E (tercera de C) (-½ tono). Este doble movimiento contrario por semitono es la resolución del tritono." },
{ q:"¿Por qué la cadencia perfecta exige los dos acordes en estado fundamental?", opts:["Por convención arbitraria","Las fundamentales V e I en el bajo crean la señal acústica más fuerte de una resolución — el bajo 'confirma' el movimiento armónico","Porque las inversiones están prohibidas","Para facilitar la lectura"], a:1, fb:"El bajo es el fundamento de la armonía. Cuando Sol (V) y Do (I) están en el bajo, el cambio de fundamental se percibe como una resolución firme y definitiva." },
{ q:"¿Qué cadencia termina tradicionalmente una pieza clásica?", opts:["Semicadencia","Cadencia plagal","Cadencia perfecta","Cadencia rota"], a:2, fb:"La cadencia perfecta (V–I, estado fundamental) es la conclusión tradicional. Aporta la resolución más firme y conclusiva — señal clara de fin de frase o de pieza." },
{ q:"La progresión Am–Dm–G7–C se analiza como:", opts:["D–T–SD–T","T–SD–D–T","SD–D–T–SD","T–D–SD–T"], a:1, fb:"Am = T (VI), Dm = SD (II), G7 = D (V), C = T (I). T–SD–D–T — es una variación del ciclo fundamental. Am como tónica inicial es frecuente en progresiones en relativo menor." },
{ q:"En G mayor, el II–V–I corresponde a:", opts:["Am–D–G","Am7–D7–GMaj7","Em–D–G","Bm–E7–A"], a:1, fb:"En G mayor: II = Am7, V = D7, I = GMaj7. La cadencia Am7–D7–GMaj7 es el II–V–I de G mayor." },
{ q:"Las cuatro voces del modelo SATB son:", opts:["Soprano, Tenor, Contralto, Barítono","Soprano, Contralto, Tenor, Bajo","Soprano, Mezzosoprano, Tenor, Bajo","Soprano, Contralto, Barítono, Bajo"], a:1, fb:"SATB = Soprano (voz femenina aguda), Contralto (voz femenina grave), Tenor (voz masculina aguda), Bajo (voz masculina grave). Cada voz tiene su propia tesitura." },
{ q:"La tesitura del soprano es:", opts:["G3 a C5","C4 a G5","C3 a G4","E2 a C4"], a:1, fb:"Soprano: C4 (Do central) a G5. Contralto: G3 a C5. Tenor: C3 a G4. Bajo: E2 a C4. Estas tesituras garantizan la comodidad vocal y el equilibrio acústico." },
{ q:"Las quintas paralelas están prohibidas porque:", opts:["Son demasiado disonantes","Anulan la independencia de las voces — dos voces en quinta paralela suenan como una sola","Crean quintas aumentadas","Son imposibles de cantar"], a:1, fb:"Las quintas paralelas dan la ilusión de que dos voces son una sola — se 'pegan' y pierden su independencia melódica. La escritura polifónica exige voces independientes." },
{ q:"El movimiento contrario entre dos voces es:", opts:["Las dos voces ascienden juntas","Las dos voces descienden juntas","Una voz asciende, la otra desciende — el movimiento más equilibrado","Una voz permanece inmóvil"], a:2, fb:"El movimiento contrario es el más equilibrado y el más favorable a la independencia de las voces. Evita naturalmente las octavas y quintas paralelas y da vitalidad a la escritura." },
{ q:"El movimiento oblicuo es:", opts:["Las dos voces que ascienden","Una voz que permanece inmóvil mientras la otra se desplaza","Las dos voces que descienden","Un salto de quinta en las dos voces"], a:1, fb:"El movimiento oblicuo: una voz sostiene una nota (o la repite) mientras la otra se desplaza. Muy frecuente en las resoluciones, especialmente para la sensible ascendente." },
{ q:"¿Por qué se favorecen los movimientos conjuntos (segundas)?", opts:["Porque son más fáciles de escribir","Porque son más naturales vocalmente y reducen los riesgos de paralelas","Porque crean más tensión","Porque son obligatorios"], a:1, fb:"Los movimientos conjuntos (por segundas) son los más naturales para las voces — cantables y fluidos. Minimizan los saltos difíciles y reducen los riesgos de octavas o quintas paralelas." },
{ q:"La regla del doblamiento en un acorde en estado fundamental es:", opts:["Doblar la tercera","Doblar la quinta","Doblar la fundamental (excepto en el VIIº grado)","Doblar la séptima"], a:2, fb:"Se dobla la fundamental por defecto — es la nota más estable. Excepción: en el VIIº grado (Bdim), se dobla la tercera (D) porque B es la sensible — nunca se dobla la sensible." },
{ q:"¿Por qué nunca se dobla la sensible?", opts:["Porque es demasiado aguda","Porque doblarla crea dos resoluciones obligatorias hacia la misma nota — problema de octavas paralelas en la resolución","Porque es demasiado grave","Porque es inestable y difícil de entonar"], a:1, fb:"Doblar la sensible crearía dos B que deben ambos ascender hacia C — produciendo octavas paralelas en la resolución. Es una falta grave en la escritura a 4 voces." },
{ q:"La separación máxima permitida entre soprano y contralto es:", opts:["Una tercera","Una quinta","Una octava","Dos octavas"], a:2, fb:"Entre soprano–contralto y entre contralto–tenor: máximo una octava. Entre tenor–bajo: hasta dos octavas toleradas. Estas proporciones mantienen el equilibrio del espectro sonoro." },
{ q:"Un cruce de voces se produce cuando:", opts:["Dos voces tocan la misma nota","La contralto canta más agudo que el soprano (o el tenor más agudo que la contralto, etc.)","Dos voces hacen un salto de quinta","El bajo asciende al registro del tenor"], a:1, fb:"El cruce de voces: una voz inferior supera a una voz superior. Ej: la contralto (G3–C5) que asciende más que el soprano actual. Prohibido en escritura estricta." },
{ q:"Un solapamiento de voces se produce cuando:", opts:["Dos voces tocan la misma nota","Una voz supera la nota que la voz adyacente acaba de dejar","Dos voces ascienden juntas","El bajo es demasiado grave"], a:1, fb:"El solapamiento: una voz 'rebasa' la nota de la voz adyacente. Ej: la contralto asciende más que la nota que el soprano acababa de dejar. Prohibido en escritura estricta." },
{ q:"En el paso II → V dentro de un II–V–I, las voces F y C (de Dm7):", opts:["Ascienden hacia G y D","Descienden: F permanece en F (7ª de G7) y C desciende hacia B (3ª de G7)","Saltan una tercera","Permanecen inmóviles"], a:1, fb:"F permanece en F (la séptima de G7). C desciende hacia B (la tercera de G7). Es el movimiento conjunto mínimo: A (5ª de Dm7) desciende hacia G (fundamental de G7). Solo dos movimientos." },
{ q:"La regla 'la séptima desciende' significa:", opts:["La séptima de cualquier acorde desciende","La séptima de dominante (F en G7) debe descender por grado conjunto (F→E) en la resolución sobre la tónica","La séptima de un acorde menor desciende","La séptima de un acorde Maj7 desciende"], a:1, fb:"La séptima de dominante (F en G7) desciende conjuntamente hacia la tercera del acorde de resolución (E en C). Regla absoluta en escritura armónica." },
{ q:"En la escritura a 4 voces, las 'octavas directas' entre soprano y bajo son:", opts:["Permitidas en todos los casos","Prohibidas en movimiento directo — toleradas si el soprano avanza por grados conjuntos","Siempre obligatorias","Permitidas únicamente en menor"], a:1, fb:"Las octavas directas (soprano y bajo que se mueven en la misma dirección para formar una octava) están generalmente prohibidas. Tolerancia única: si el soprano avanza por semitono o tono." },
{ q:"¿Por qué se deben evitar los movimientos disjuntos (grandes intervalos) en las voces interiores?", opts:["Porque crean consonancias","Porque crean riesgos de paralelas, son difíciles de cantar y rompen la fluidez melódica","Porque son demasiado cortos","Porque crean demasiadas disonancias"], a:1, fb:"Los saltos grandes en las voces interiores (contralto, tenor) rompen la fluidez, son difíciles de entonar y aumentan los riesgos de errores (paralelas, solapamientos). Los grandes intervalos se reservan para el bajo." },
{ q:"La segunda aumentada es:", opts:["Un intervalo diatónico normal","Un intervalo a evitar en escritura vocal — difícil de entonar (aparece entre el VI y VII de menor armónica)","Un intervalo siempre permitido en contrapunto","Un intervalo de 2 semitonos"], a:1, fb:"La segunda aumentada = 3 semitonos (entre el VI♭ y el VII natural de la escala menor armónica, ej: Lab–B en C menor). Es difícil de entonar y suena artificial en escritura vocal. En armonía estricta se evita en las líneas melódicas." },
];

const questionsDe: Question[] = [{ q:"Wie viele Ganztöne enthält der Tritonus?", opts:["2","3","4","6"], a:1, fb:"Der Tritonus = 3 Ganztöne (6 Halbtonschritte). Sein Name kommt daher — Tri-ton. In C-Dur entsteht er zwischen F und B." },
{ q:"Welche Noten bilden in C-Dur den Tritonus?", opts:["C und G","F und B","E und A","D und A"], a:1, fb:"F (IV. Stufe) und B (VII. Stufe) sind die beiden Noten des Tritonus in C-Dur. Es sind die charakteristischen Töne des Akkords G7." },
{ q:"Warum ist der Tritonus instabil?", opts:["Weil er sehr tief ist","Weil er auf halbem Weg der Oktave liegt — seine akustische Mehrdeutigkeit erzeugt eine starke Spannung zur Auflösung","Weil er immer Vorzeichen enthält","Weil er in der Musik selten vorkommt"], a:1, fb:"Der Tritonus teilt die Oktave in zwei gleiche Hälften (6+6 Halbtonschritte) — er ist vollkommen symmetrisch. Dieses Fehlen einer Richtung erzeugt eine Spannung, die eine Auflösung verlangt." },
{ q:"Zu welchen Stufen löst der Tritonus natürlich auf?", opts:["Zu V und VII","Zu I und III (oder ihrem Äquivalent)","Zu II und IV","Zu VI und VII"], a:1, fb:"Der Tritonus F–B löst sich durch Halbtonschritte auf: F fällt nach E (Terz von C) und B steigt nach C (Tonika). Die Auflösung zielt auf die Stufen I und III." },
{ q:"In G7 ist die Note F:", opts:["Die Grundnote","Die Terz","Die Quinte","Die Septime"], a:3, fb:"G7 = G–B–D–F. F ist die (kleine) Septime von G7. Sie ist eine Hälfte des Tritonus — sie muss bei der Auflösung nach E fallen." },
{ q:"In G7 ist die Note B:", opts:["Die Grundnote","Die Terz","Die Quinte","Die Septime"], a:1, fb:"G7 = G–B–D–F. B ist die Terz von G7 — und der Leitton von C-Dur. Er muss bei der Auflösung nach C steigen." },
{ q:"Bei der Auflösung G7 → C steigt der Leitton B:", opts:["Fällt nach G","Steigt um einen Halbton nach C","Bleibt auf B","Springt nach E"], a:1, fb:"B (Leitton) steigt obligatorisch nach C (Tonika). Dieser aufsteigende Halbtonschritt ist die Auflösung des Leittons — eine absolute Regel der tonalen Harmonik." },
{ q:"Bei der Auflösung G7 → C fällt die Septime F:", opts:["Steigt nach G","Fällt stufenweise nach E","Bleibt auf F","Springt nach C"], a:1, fb:"F (Dominantseptime) fällt nach E (Terz von C). Dieser absteigende Halbtonschritt ist die Auflösung der Septime — eine absolute Regel." },
{ q:"Der Tritonus in G-Dur wird gebildet durch:", opts:["G und D","C und F#","B und E","A und D"], a:1, fb:"In G-Dur bilden IV (C) und VII (F#) den Tritonus. C–F# = 6 Halbtonschritte = Tritonus." },
{ q:"Welcher Akkord in C-Dur enthält beide Noten des Tritonus (F und B)?", opts:["C","F","G7","Am"], a:2, fb:"G7 = G–B–D–F. Er enthält B (Leitton) und F (Dominantseptime) — den vollständigen Tritonus. Deshalb ist G7 die vollkommene Dominante." },
{ q:"Seit wie vielen Jahrhunderten gilt der Tritonus in der westlichen Musik als instabil?", opts:["Seit etwa 100 Jahren","Seit etwa 400 Jahren","Seit etwa 1 000 Jahren","Seit jeher"], a:1, fb:"Seit etwa 400 Jahren (Barockmusik) steht der Tritonus im Mittelpunkt der harmonischen Spannung der tonalen Musik. Die Funktionsharmonik beruht auf dieser Instabilität." },
{ q:"Die Auflösung des Tritonus F–B erfolgt durch:", opts:["Zwei aufsteigende Bewegungen","Zwei absteigende Bewegungen","Eine aufsteigende Bewegung (B→C) und eine absteigende (F→E) — Gegenbewegung","Zwei Quintensprünge"], a:2, fb:"B steigt nach C (+½ Ton) und F fällt nach E (-½ Ton). Diese doppelte Gegenbewegung um Halbtonschritte ist die Auflösung des Tritonus — sehr stabil, weil symmetrisch." },
{ q:"Enthält der Akkord Bdim den Tritonus von C-Dur?", opts:["Nein","Ja — er enthält B und F, die beiden Noten des Tritonus","Er enthält F, aber nicht B","Er enthält B, aber nicht F"], a:1, fb:"Bdim = B–D–F. Er enthält tatsächlich B (Leitton) und F (Subdominante) — den vollständigen Tritonus. Deshalb ist Bdim eine funktionale Alternative zu G7: beide sind Dominante." },
{ q:"Der Tritonus wird auch genannt:", opts:["Verminderte Quarte","Verminderte Quinte oder übermäßige Quarte","Kleine Sexte","Verminderte Septime"], a:1, fb:"Der Tritonus = übermäßige Quarte (F–B aufsteigend) oder verminderte Quinte (B–F absteigend). In beiden Fällen 6 Halbtonschritte — gleicher Intervall, unterschiedliche Namen je nach Richtung." },
{ q:"Welche Noten bilden in F-Dur den Tritonus?", opts:["F und C","Bb und E","G und D","A und Eb"], a:1, fb:"In F-Dur sind IV = Bb und VII = E. Der Tritonus von F-Dur ist Bb–E (6 Halbtonschritte). Der Dominantakkord von F ist C7, der Bb und E enthält." },
{ q:"Warum ist der Tritonus der Schlüssel zur Funktionsharmonik?", opts:["Weil er selten ist","Weil seine Anwesenheit oder Abwesenheit die Funktionen T, SD und D definiert — er organisiert die gesamte harmonische Spannung","Weil er Vierklänge erzeugt","Weil er ausschließlich zur Molltonleiter gehört"], a:1, fb:"Beide Tritonusnoten vorhanden → Dominante. Nur eine → Subdominante. Keine → Tonika. Der Tritonus ist der 'Thermostat' der harmonischen Spannung." },

{ q:"Wie viele Hauptfunktionen der Tonalität gibt es?", opts:["2","3","4","5"], a:1, fb:"Drei Funktionen: Tonika (T), Subdominante (SD), Dominante (D). Sie ordnen alle Akkorde gemäß ihrer Rolle in Spannung und Auflösung." },
{ q:"Die Tonikafunktion ist gekennzeichnet durch:", opts:["Das Vorhandensein des vollständigen Tritonus","Das Fehlen von F und B — Stabilität, Auflösung, Ruhe","Das Vorhandensein von F allein","Das Vorhandensein von B allein"], a:1, fb:"Die Tonika enthält keine der beiden Tritonusnoten (weder F noch B). Sie ist stabil — sie ist der Ruhepunkt und die Auflösung. In C: I (C) und VI (Am)." },
{ q:"Die Subdominantfunktion ist gekennzeichnet durch:", opts:["Das Vorhandensein des vollständigen Tritonus","Das Vorhandensein von F (IV. Stufe), aber nicht von B","Das Vorhandensein von B, aber nicht von F","Das Fehlen von F und B"], a:1, fb:"Die Subdominante enthält F (Subdominante), aber nicht B (Leitton). Sie bereitet die Spannung vor, ohne deren Höhepunkt zu sein. In C: II (Dm) und IV (F)." },
{ q:"Die Dominantfunktion ist gekennzeichnet durch:", opts:["Das Fehlen des Tritonus","Das Vorhandensein von F allein","Das Vorhandensein des vollständigen Tritonus (F und B)","Das Vorhandensein von B allein"], a:2, fb:"Die Dominante enthält beide Tritonusnoten (F und B). Sie ist der Höhepunkt der Spannung — sie verlangt zwingend die Auflösung auf die Tonika. In C: V (G7) und VII (Bdim)." },
{ q:"Welche Akkorde haben in C-Dur die Tonikafunktion?", opts:["C und G","Dm und F","C und Am","G7 und Bdim"], a:2, fb:"C (I) und Am (VI): keiner enthält F oder B. Das sind die beiden Tonika-Akkorde von C-Dur. Am ist eine 'sanfte' Tonika, oft in Trugschlüssen verwendet." },
{ q:"Welche Akkorde haben in C-Dur die Dominantfunktion?", opts:["G7 und Am","G7 und Bdim","C und Em","Dm und F"], a:1, fb:"G7 (V) und Bdim (VII) enthalten beide F und B — den vollständigen Tritonus. Das sind die beiden Dominanten von C-Dur." },
{ q:"Welche Akkorde haben in C-Dur die Subdominantfunktion?", opts:["C und Am","G7 und Bdim","Dm und F","Em und G"], a:2, fb:"Dm (II) und F (IV) enthalten F, aber nicht B. Das sind die beiden Subdominanten von C-Dur." },
{ q:"Die grundlegende Akkordfolge der Funktionsharmonik ist:", opts:["T → D → SD","SD → D → T","D → T → SD","T → SD → T"], a:1, fb:"SD → D → T ist das 'Rückgrat' der tonalen Harmonik. Die Subdominante bereitet die Dominante vor, die sich auf die Tonika auflöst." },
{ q:"Was ist eine diatonische Substitution?", opts:["Ein umgekehrter Akkord","Einen Akkord durch einen anderen mit gleicher Funktion in derselben Tonart ersetzen","Ein aus einer anderen Tonart entliehener Akkord","Ein Vierklang"], a:1, fb:"Eine diatonische Substitution ersetzt einen Akkord durch einen anderen mit gleicher Funktion in derselben Tonart. Bsp.: Am kann C ersetzen (beide = Tonika in C)." },
{ q:"In C-Dur kann Dm F ersetzen, weil:", opts:["Sie die gleiche Grundnote haben","Beide die Subdominantfunktion haben — sie enthalten F, aber nicht B","Sie die gleichen Noten haben","Sie eine Quinte voneinander entfernt sind"], a:1, fb:"Dm (II) und F (IV) haben beide die Subdominantfunktion: Sie enthalten F (IV. Stufe), aber nicht B. Sie können sich daher gegenseitig ersetzen, ohne die funktionale Logik zu verändern." },
{ q:"In C-Dur kann Am C ersetzen, weil:", opts:["Am tiefer liegt","Beide die Tonikafunktion haben — weder F noch B","Am stabiler ist","Sie die gleiche Grundnote haben"], a:1, fb:"Am (VI) und C (I) haben beide die Tonikafunktion. Der Trugschluss (G7 → Am statt G7 → C) nutzt diese Substitution, um einen Überraschungseffekt zu erzeugen." },
{ q:"Warum wird Em als 'Bastard'-Akkord bezeichnet?", opts:["Weil er vermindert ist","Weil er nur B (den Leitton) enthält, ohne F — seine Funktion ist mehrdeutig und er wird selten allein verwendet","Weil er zu hoch ist","Weil er nicht zu C-Dur gehört"], a:1, fb:"Em (III) enthält B (Leitton von C), aber nicht F (Subdominante). Er lässt sich daher keiner der drei Funktionen klar zuordnen. Komponisten sind sich über seine Rolle uneinig." },
{ q:"Die Progression I–VI–II–V–I in C lautet funktional:", opts:["T–D–SD–D–T","T–T–SD–D–T","SD–D–T–D–T","T–D–T–SD–T"], a:1, fb:"C(T) – Am(T) – Dm(SD) – G(D) – C(T) = T–T–SD–D–T. Die beiden Tonika-Akkorde folgen aufeinander (I und VI), dann folgt der Zyklus SD–D–T." },
{ q:"Warum ist eine Aneinanderreihung von nur Tonika-Akkorden langweilig?", opts:["Weil Tonika-Akkorde dissonant sind","Weil die Musik ohne Spannung zu stabil wird — es gibt keine Bewegung","Weil Tonika-Akkorde instabil sind","Weil man nicht darüber singen kann"], a:1, fb:"Musik lebt vom Kontrast zwischen Spannung und Auflösung. Nur Tonika = zu viel Stabilität, kein Schwung. Nur Dominante = zu viel Unbehagen. Die Balance ist entscheidend." },
{ q:"Die 'emotionale Farbe' einer Progression wird bestimmt durch:", opts:["Ihr Tempo","Die Auflösung — der Tonika-Akkord und seine Dur- oder Mollfarbe","Die Anzahl der Akkorde","Die Tonhöhe der Noten"], a:1, fb:"In der Funktionsharmonik kommt die Emotion aus der Auflösung — welche Farbe an der Tonika ankommt. Die Spannung (Dominante) erzeugt die Erwartung, die Auflösung (Tonika) gibt die emotionale Farbe." },
{ q:"Warum ist G7 → Am ein Trugschluss?", opts:["Weil G7 falsch aufgelöst wird","Weil das Ohr C (Haupttonika) erwartete, aber Am erhält — harmonische Überraschung","Weil Am nicht in C-Dur ist","Weil G7 nicht die Dominante ist"], a:1, fb:"Der Trugschluss täuscht die Erwartungen: G7 (Dominante) sollte sich auf C (Tonika) auflösen. Indem er nach Am (Substitutionstonika) geht, entsteht eine Überraschung, die die Phrase verlängert." },
{ q:"In G-Dur ist die Dominante:", opts:["D","D7","C","A7"], a:1, fb:"In G-Dur ist V = D. Mit der Septime: D7 (D–F#–A–C). D7 enthält den Tritonus von G-Dur (C und F#) — er löst sich auf G auf." },
{ q:"Die Progression Dm–G7–C wird analysiert als:", opts:["T–D–SD","SD–D–T","D–T–SD","T–SD–D"], a:1, fb:"Dm = Subdominante (II), G7 = Dominante (V), C = Tonika (I). SD–D–T ist die Grundfolge — das ist die II–V–I-Kadenz." },
{ q:"Was ist der funktionale Unterschied zwischen G und G7 in C-Dur?", opts:["Keiner","G7 ist instabiler — er enthält den vollständigen Tritonus (F), G enthält ihn nicht","G ist instabiler","G7 ist eine Tonika"], a:1, fb:"G (G–B–D) enthält B (Leitton), aber nicht F. G7 (G–B–D–F) enthält beide Tritonusnoten. G7 ist deutlich spannungsreicher und löst sich viel stärker nach C auf." },
{ q:"Welche Noten bilden in D-Dur den Tritonus (IV. und VII. Stufe)?", opts:["D und A","G und C#","F# und B","E und A"], a:1, fb:"In D-Dur ist IV = G und VII = C#. G–C# = 6 Halbtonschritte = Tritonus. Die Dominante von D-Dur ist A7, der G und C# enthält." },

{ q:"Eine vollkommene Kadenz ist:", opts:["IV → I","V → I mit beiden Akkorden im Grundzustand","V → VI","II → V"], a:1, fb:"Vollkommene Kadenz = V → I, beide im Grundzustand. Das ist die abschließendste Kadenz — G7 (Grundzustand) → C (Grundzustand) in C-Dur." },
{ q:"Eine unvollkommene Kadenz unterscheidet sich von der vollkommenen, weil:", opts:["Sie IV statt V verwendet","Mindestens einer der beiden Akkorde umgekehrt ist","Sie auf VI auflöst","Sie in Moll steht"], a:1, fb:"Unvollkommene Kadenz = V → I, aber mindestens ein Akkord ist umgekehrt. Die Auflösung ist wahrnehmbar, aber weniger fest als mit beiden Akkorden im Grundzustand." },
{ q:"Eine plagale Kadenz ist:", opts:["V → I","IV → I — sanft und feierlich","II → V","V → VI"], a:1, fb:"Plagale Kadenz = IV → I (F → C in C-Dur). Ihre sanfte und feierliche Farbe brachte ihr den Beinamen 'Amen'-Kadenz ein — sehr präsent in der Kirchenmusik." },
{ q:"Eine Halbkadenz endet auf:", opts:["I","II","IV","V — die Phrase bleibt schwebend"], a:3, fb:"Die Halbkadenz endet auf der Dominante (V) ohne Auflösung. Es ist eine Suspension — wie eine Frage, die unbeantwortet bleibt. Das Ohr erwartet die Fortsetzung." },
{ q:"Die Trugkadenz V → VI erzeugt einen Effekt von:", opts:["Starker Auflösung","Überraschung — das Ohr erwartete I, erhält aber VI","Maximaler Instabilität","Endgültigem Schluss"], a:1, fb:"Die Trugkadenz unterwandert die Erwartungen — V sollte auf I auflösen, geht aber stattdessen auf VI. Der Überraschungseffekt ermöglicht es, die Phrase fortzusetzen, ohne zu schließen." },
{ q:"Der absteigende Quintenzirkel ist:", opts:["I–II–III–IV–V–VI–VII","I–IV–VII–III–VI–II–V–I — jeder Akkord fällt um eine Quinte","V–IV–III–II–I","I–V–IV–I"], a:1, fb:"I–IV–VII–III–VI–II–V–I: Jeder Akkord fällt um eine Quinte (oder steigt um eine Quarte) gegenüber dem vorherigen. Diese Quintbewegung ist die natürlichste und stärkste der Harmonik." },
{ q:"Die 'Pendel'-Technik besteht darin:", opts:["Ausschließlich zwischen Dominante und Tonika zu wechseln","Zwischen zwei Funktionen zu wechseln (z. B. T–SD–T–SD), bevor man voranschreitet","Denselben Akkord endlos zu wiederholen","Die Tonart bei jedem Takt zu wechseln"], a:1, fb:"Das Pendel wechselt zwischen zwei Funktionen (oft T–SD oder T–D) und erzeugt einen Schwingungseffekt. Bsp.: C–Am–F–C–Am–F… vor einer abschließenden Kadenz G7–C." },
{ q:"Funktionserweiterung bedeutet:", opts:["Einen Akkord zweimal zu wiederholen","Mehrere Akkorde gleicher Funktion aneinanderzureihen, um sie zu verlängern","Die Bassnote eines Akkords zu ändern","Einen Akkord umzukehren"], a:1, fb:"Man kann eine Funktion verlängern, indem man mehrere Akkorde gleicher Rolle aneinanderreiht. Bsp.: Dm–F–G7–C = SD–SD–D–T. Die beiden Subdominanten geben der Vorbereitung mehr Gewicht." },
{ q:"Welcher Akkord folgt im Quintenzirkel in C-Dur auf Dm?", opts:["C","G","Am","Bdim"], a:1, fb:"I–IV–VII–III–VI–II–V–I. Dm ist die II. Stufe. Der nächste im Zyklus = V. Stufe = G. Dm → G: die Grundnote fällt um eine Quinte (D → G)." },
{ q:"Die Progression ii–V–I (2–5–1) ist grundlegend, weil:", opts:["Sie drei Akkorde verwendet","SD → D → T in Vierklängen, mit gemeinsamen Noten, die die Stimmführung optimieren","Sie in Moll ist","Sie den Tritonus zweimal verwendet"], a:1, fb:"II–V–I = SD–D–T in erweiterter Form (Vierklänge). Die gemeinsamen Noten zwischen Dm7 und G7 (D und F) ermöglichen eine minimale Stimmführung — das ist die effizienteste Kadenz der tonalen Musik." },
{ q:"Wie viele gemeinsame Noten haben Dm7 und G7 in C-Dur?", opts:["0","1","2","4"], a:2, fb:"Dm7 = D–F–A–C. G7 = G–B–D–F. Gemeinsame Noten: D und F (2 Noten). Diese zwei Noten können gehalten werden, und nur A–C müssen sich nach B–G bewegen." },
{ q:"Um beim minimalen II–V–I von II nach V zu gelangen, welche Stimmen müssen sich bewegen?", opts:["Alle Stimmen","Nur Grundnote und Terz — die beiden anderen bleiben liegen","Keine Stimme bewegt sich","Alle außer dem Bass"], a:1, fb:"Von Dm7 (D–F–A–C) nach G7 (G–B–D–F): D bleibt, F bleibt. Nur A fällt nach G und C fällt nach B. Minimale Stimmführung — zwei absteigende Sekundschritte." },
{ q:"Die Progression C–Am–F–G ist funktional:", opts:["T–D–SD–D","T–T–SD–D","SD–T–D–T","D–T–SD–T"], a:1, fb:"C = T, Am = T (diatonische Substitution), F = SD, G = D. T–T–SD–D — das ist das harmonische Grundmuster vieler moderner Popsongs." },
{ q:"Bei der Progression G7 → C löst sich der Tritonus auf durch:", opts:["Zwei aufsteigende Bewegungen","Zwei absteigende Bewegungen","Gegenbewegung: B steigt nach C (+½), F fällt nach E (-½)","Zwei Terzsprünge"], a:2, fb:"B (Terz von G7, Leitton) steigt nach C (+½ Ton). F (Septime von G7) fällt nach E (Terz von C) (-½ Ton). Diese doppelte Gegenbewegung um Halbtonschritte ist die Auflösung des Tritonus." },
{ q:"Warum verlangt die vollkommene Kadenz beide Akkorde im Grundzustand?", opts:["Aus willkürlicher Konvention","Die Grundnoten V und I im Bass erzeugen das stärkste akustische Signal einer Auflösung — der Bass 'bestätigt' die harmonische Bewegung","Weil Umkehrungen verboten sind","Um das Lesen zu erleichtern"], a:1, fb:"Der Bass ist das Fundament der Harmonik. Wenn Sol (V) und Do (I) im Bass liegen, wird der Wechsel der Grundnote als feste und endgültige Auflösung wahrgenommen." },
{ q:"Welche Kadenz beendet traditionell ein klassisches Stück?", opts:["Halbkadenz","Plagale Kadenz","Vollkommene Kadenz","Trugkadenz"], a:2, fb:"Die vollkommene Kadenz (V–I, Grundzustand) ist der traditionelle Abschluss. Sie bringt die festeste und abschließendste Auflösung — klares Signal für das Ende einer Phrase oder eines Stückes." },
{ q:"Die Progression Am–Dm–G7–C wird analysiert als:", opts:["D–T–SD–T","T–SD–D–T","SD–D–T–SD","T–D–SD–T"], a:1, fb:"Am = T (VI), Dm = SD (II), G7 = D (V), C = T (I). T–SD–D–T — das ist eine Variation des Grundzyklus. Am als Ausgangstonika ist häufig in Progressionen in der Parallelmolltonart." },
{ q:"In G-Dur entspricht das II–V–I:", opts:["Am–D–G","Am7–D7–GMaj7","Em–D–G","Bm–E7–A"], a:1, fb:"In G-Dur: II = Am7, V = D7, I = GMaj7. Die Kadenz Am7–D7–GMaj7 ist das II–V–I von G-Dur." },

{ q:"Die vier Stimmen des SATB-Modells sind:", opts:["Sopran, Tenor, Alt, Bariton","Sopran, Alt, Tenor, Bass","Sopran, Mezzosopran, Tenor, Bass","Sopran, Alt, Bariton, Bass"], a:1, fb:"SATB = Sopran (hohe Frauenstimme), Alt (tiefe Frauenstimme), Tenor (hohe Männerstimme), Bass (tiefe Männerstimme). Jede Stimme hat ihre eigene Tessitur." },
{ q:"Die Tessitur des Soprans ist:", opts:["G3 bis C5","C4 bis G5","C3 bis G4","E2 bis C4"], a:1, fb:"Sopran: C4 (mittleres C) bis G5. Alt: G3 bis C5. Tenor: C3 bis G4. Bass: E2 bis C4. Diese Tessituren gewährleisten stimmlichen Komfort und akustisches Gleichgewicht." },
{ q:"Parallele Quinten sind verboten, weil:", opts:["Sie zu dissonant sind","Sie die Unabhängigkeit der Stimmen aufheben — zwei Stimmen in parallelen Quinten klingen wie eine einzige","Sie übermäßige Quinten erzeugen","Sie unsingbar sind"], a:1, fb:"Parallele Quinten erwecken den Eindruck, dass zwei Stimmen zu einer verschmelzen — sie 'kleben' zusammen und verlieren ihre melodische Unabhängigkeit. Polyphones Schreiben erfordert unabhängige Stimmen." },
{ q:"Gegenbewegung zwischen zwei Stimmen bedeutet:", opts:["Beide Stimmen steigen gemeinsam","Beide Stimmen fallen gemeinsam","Eine Stimme steigt, die andere fällt — die ausgewogenste Bewegung","Eine Stimme bleibt ruhig"], a:2, fb:"Die Gegenbewegung ist die ausgewogenste und für die Unabhängigkeit der Stimmen günstigste. Sie vermeidet natürlich parallele Oktaven und Quinten und verleiht dem Satz Lebendigkeit." },
{ q:"Seitenbewegung bedeutet:", opts:["Beide Stimmen steigen","Eine Stimme bleibt ruhig, während die andere sich bewegt","Beide Stimmen fallen","Ein Quintsprung in beiden Stimmen"], a:1, fb:"Seitenbewegung: eine Stimme hält eine Note (oder wiederholt sie), während die andere sich bewegt. Sehr häufig bei Auflösungen, insbesondere beim aufsteigenden Leitton." },
{ q:"Warum bevorzugt man Stufenbewegungen (Sekunden)?", opts:["Weil sie leichter zu schreiben sind","Weil sie stimmlich natürlicher sind und das Risiko von Parallelen verringern","Weil sie mehr Spannung erzeugen","Weil sie obligatorisch sind"], a:1, fb:"Stufenbewegungen (Sekunden) sind für die Stimmen am natürlichsten — singbar und fließend. Sie minimieren schwierige Sprünge und verringern das Risiko von Oktav- oder Quintparallelen." },
{ q:"Die Verdopplungsregel bei einem Akkord im Grundzustand lautet:", opts:["Die Terz verdoppeln","Die Quinte verdoppeln","Die Grundnote verdoppeln (außer bei der VII. Stufe)","Die Septime verdoppeln"], a:2, fb:"Man verdoppelt standardmäßig die Grundnote — sie ist die stabilste Note. Ausnahme: bei der VII. Stufe (Bdim) verdoppelt man die Terz (D), da B der Leitton ist — man verdoppelt niemals den Leitton." },
{ q:"Warum verdoppelt man den Leitton niemals?", opts:["Weil er zu hoch ist","Weil seine Verdoppelung zwei obligatorische Auflösungen zur selben Note erzeugt — Problem der Parallelokaven bei der Auflösung","Weil er zu tief ist","Weil er instabil und schwer zu intonieren ist"], a:1, fb:"Den Leitton zu verdoppeln würde zwei B erzeugen, die beide nach C steigen müssen — was Paralleloktaven bei der Auflösung ergibt. Das ist ein schwerer Fehler im vierstimmigen Satz." },
];

const questionsIt: Question[] = [{ q:"Quante tone contiene il tritono?", opts:["2","3","4","6"], a:1, fb:"Il tritono = 3 toni (6 semitoni). Il suo nome deriva da lì — tri-tono. In C maggiore, si forma tra F e B." },
{ q:"In C maggiore, quali note formano il tritono?", opts:["C e G","F e B","E e A","D e A"], a:1, fb:"F (Fa, IV grado) e B (Si, VII grado) sono le due note del tritono di C maggiore. Sono le note costitutive dell'accordo G7." },
{ q:"Perché il tritono è instabile?", opts:["Perché è molto grave","Perché si trova a metà dell'ottava — la sua ambiguità acustica crea una forte tensione verso la risoluzione","Perché contiene sempre dei bemolli","Perché è raro in musica"], a:1, fb:"Il tritono divide l'ottava in due parti uguali (6+6 semitoni) — è perfettamente simmetrico. Questa assenza di direzione crea una tensione che richiede una risoluzione." },
{ q:"Verso quali gradi il tritono si risolve naturalmente?", opts:["Verso V e VII","Verso I e III (o il loro equivalente)","Verso II e IV","Verso VI e VII"], a:1, fb:"Il tritono F–B si risolve per semitono congiunto: F scende verso E (terza di C) e B sale verso C (tonica). La risoluzione punta ai gradi I e III." },
{ q:"In G7, la nota F è:", opts:["La fondamentale","La terza","La quinta","La settima"], a:3, fb:"G7 = G–B–D–F. F è la settima (minore) di G7. È una delle due note del tritono — deve scendere verso E durante la risoluzione." },
{ q:"In G7, la nota B è:", opts:["La fondamentale","La terza","La quinta","La settima"], a:1, fb:"G7 = G–B–D–F. B è la terza di G7 — ed è la sensibile di C maggiore. Deve salire verso C durante la risoluzione." },
{ q:"Durante la risoluzione G7 → C, la sensibile B:", opts:["Scende verso G","Sale verso C per semitono","Rimane su B","Salta verso E"], a:1, fb:"B (sensibile) sale obbligatoriamente verso C (tonica). Questo semitono ascendente è la risoluzione della sensibile — regola assoluta dell'armonia tonale." },
{ q:"Durante la risoluzione G7 → C, la settima F:", opts:["Sale verso G","Scende verso E per grado congiunto","Rimane su F","Salta verso C"], a:1, fb:"F (settima di dominante) scende verso E (terza di C). Questo semitono discendente è la risoluzione della settima — regola assoluta." },
{ q:"Il tritono di G maggiore è formato da:", opts:["G e D","C e F#","B e E","A e D"], a:1, fb:"In G maggiore, il IV grado (C) e il VII grado (F#) formano il tritono. C–F# = 6 semitoni = tritono." },
{ q:"Quale accordo di C maggiore contiene le due note del tritono (F e B)?", opts:["C","F","G7","Am"], a:2, fb:"G7 = G–B–D–F. Contiene B (sensibile) e F (7a di dominante) — il tritono completo. Ecco perché G7 è la dominante perfetta." },
{ q:"Da quanti secoli il tritono è instabile nella musica occidentale?", opts:["Circa 100 anni","Circa 400 anni","Circa 1 000 anni","Da sempre"], a:1, fb:"Da circa 400 anni (musica barocca), il tritono è al centro della tensione armonica della musica tonale. L'armonia funzionale si basa su questa instabilità." },
{ q:"La risoluzione del tritono F–B avviene per:", opts:["Due movimenti ascendenti","Due movimenti discendenti","Un movimento ascendente (B→C) e uno discendente (F→E) — movimenti contrari","Due salti di quinta"], a:2, fb:"B sale verso C (+½ tono) e F scende verso E (-½ tono). Questo doppio movimento contrario per semitono è la risoluzione del tritono — molto stabile perché simmetrico." },
{ q:"L'accordo Bdim contiene il tritono di C maggiore?", opts:["No","Sì — contiene B e F, le due note del tritono","Contiene F ma non B","Contiene B ma non F"], a:1, fb:"Bdim = B–D–F. Contiene sia B (sensibile) che F (sottodominante) — il tritono completo. Ecco perché Bdim è un'alternativa funzionale a G7: entrambi svolgono la funzione di dominante." },
{ q:"Il tritono è chiamato anche:", opts:["Quarta diminuita","Quinta diminuita o quarta aumentata","Sesta minore","Settima diminuita"], a:1, fb:"Il tritono = quarta aumentata (F–B ascendente) o quinta diminuita (B–F discendente). 6 semitoni in entrambi i casi — stesso intervallo, nomi diversi a seconda della direzione." },
{ q:"In F maggiore, quali note formano il tritono?", opts:["F e C","Bb e E","G e D","A e Eb"], a:1, fb:"In F maggiore, IV = Bb e VII = E. Il tritono di F maggiore è Bb–E (6 semitoni). L'accordo di dominante di F è C7, che contiene Bb e E." },
{ q:"Perché il tritono è la chiave dell'armonia funzionale?", opts:["Perché è raro","Perché la sua presenza o assenza definisce le funzioni T, SD e D — organizza tutta la tensione armonica","Perché crea accordi a 4 note","Perché appartiene solo alla scala minore"], a:1, fb:"La presenza di entrambe le note del tritono → Dominante. Una sola → Sottodominante. Nessuna → Tonica. Il tritono è il 'termostato' della tensione armonica." },
{ q:"Quante funzioni tonali principali esistono?", opts:["2","3","4","5"], a:1, fb:"Tre funzioni: Tonica (T), Sottodominante (SD), Dominante (D). Esse organizzano tutti gli accordi secondo il loro ruolo nella tensione/risoluzione." },
{ q:"La funzione Tonica è caratterizzata da:", opts:["La presenza del tritono completo","L'assenza di F e B — stabilità, risoluzione, riposo","La presenza di F da sola","La presenza di B da sola"], a:1, fb:"La Tonica non contiene nessuna delle due note del tritono (né F né B). È stabile — è il punto di riposo e di risoluzione. In C: I (C) e VI (Am)." },
{ q:"La funzione Sottodominante è caratterizzata da:", opts:["La presenza del tritono completo","La presenza di F (IV grado) ma non di B","La presenza di B ma non di F","L'assenza di F e B"], a:1, fb:"La Sottodominante contiene F (sottodominante) ma non B (sensibile). Prepara la tensione senza esserne il culmine. In C: II (Dm) e IV (F)." },
{ q:"La funzione Dominante è caratterizzata da:", opts:["L'assenza di tritono","La presenza di F da sola","La presenza del tritono completo (F e B)","La presenza di B da sola"], a:2, fb:"La Dominante contiene entrambe le note del tritono (F e B). È il culmine della tensione — chiede imperativamente la risoluzione sulla Tonica. In C: V (G7) e VII (Bdim)." },
{ q:"In C maggiore, quali accordi hanno la funzione Tonica?", opts:["C e G","Dm e F","C e Am","G7 e Bdim"], a:2, fb:"C (I) e Am (VI): nessuno dei due contiene F né B. Sono le due toniche di C maggiore. Am è una tonica 'dolce', spesso usata nelle cadenze d'inganno." },
{ q:"In C maggiore, quali accordi hanno la funzione Dominante?", opts:["G7 e Am","G7 e Bdim","C e Em","Dm e F"], a:1, fb:"G7 (V) e Bdim (VII) contengono entrambi F e B — il tritono completo. Sono le due dominanti di C maggiore." },
{ q:"In C maggiore, quali accordi hanno la funzione Sottodominante?", opts:["C e Am","G7 e Bdim","Dm e F","Em e G"], a:2, fb:"Dm (II) e F (IV) contengono F ma non B. Sono le due sottodominanti di C maggiore." },
{ q:"L'incatenamento fondamentale dell'armonia tonale è:", opts:["T → D → SD","SD → D → T","D → T → SD","T → SD → T"], a:1, fb:"SD → D → T è la 'spina dorsale' dell'armonia tonale. La Sottodominante prepara la Dominante che si risolve sulla Tonica." },
{ q:"Cos'è una sostituzione diatonica?", opts:["Un accordo rivolto","Sostituire un accordo con un altro della stessa funzione nella stessa scala","Un accordo preso in prestito da un'altra scala","Un accordo a 4 suoni"], a:1, fb:"Una sostituzione diatonica sostituisce un accordo con un altro della stessa funzione nella stessa scala. Es: Am può sostituire C (entrambi = Tonica in C)." },
{ q:"In C maggiore, Dm può sostituire F perché:", opts:["Hanno la stessa fondamentale","Entrambi hanno la funzione Sottodominante — contengono F ma non B","Hanno le stesse note","Sono a distanza di quinta l'uno dall'altro"], a:1, fb:"Dm (II) e F (IV) hanno entrambi la funzione Sottodominante: contengono F (IV grado) ma non B. Possono quindi sostituirsi a vicenda senza cambiare la logica funzionale." },
{ q:"In C maggiore, Am può sostituire C perché:", opts:["Am è più grave","Entrambi hanno la funzione Tonica — né F né B","Am è più stabile","Hanno la stessa fondamentale"], a:1, fb:"Am (VI) e C (I) hanno entrambi la funzione Tonica. La cadenza d'inganno (G7 → Am invece di G7 → C) sfrutta questa sostituzione per creare un effetto a sorpresa." },
{ q:"Perché Em è definito accordo 'bastardo'?", opts:["Perché è diminuito","Perché contiene solo B (la sensibile) senza F — la sua funzione è ambigua e viene raramente usato da solo","Perché è troppo acuto","Perché non appartiene a C maggiore"], a:1, fb:"Em (III) contiene B (sensibile di C) ma non F (sottodominante). Non rientra chiaramente in nessuna delle tre funzioni. I compositori non concordano sul suo ruolo." },
{ q:"La progressione I–VI–II–V–I in C è:", opts:["T–D–SD–D–T","T–T–SD–D–T","SD–D–T–D–T","T–D–T–SD–T"], a:1, fb:"C(T) – Am(T) – Dm(SD) – G(D) – C(T) = T–T–SD–D–T. Le due toniche si incatenano (I e VI), poi si segue il ciclo SD–D–T." },
{ q:"Perché incatenare solo toniche è noioso?", opts:["Perché le toniche sono dissonanti","Perché la musica diventa troppo stabile senza tensione — non c'è movimento","Perché le toniche sono instabili","Perché non ci si può cantare sopra"], a:1, fb:"La musica funziona per contrasto tra tensione e risoluzione. Solo toniche = troppa stabilità, nessuno slancio. Solo dominanti = troppo disagio. L'equilibrio è essenziale." },
{ q:"Il 'colore emotivo' di una progressione è determinato da:", opts:["Il suo tempo","La risoluzione — l'accordo di tonica e il suo colore maggiore o minore","Il numero di accordi","L'altezza delle note"], a:1, fb:"Nell'armonia funzionale, l'emozione viene dalla risoluzione — quale colore arriva alla tonica. La tensione (Dominante) crea l'attesa, la risoluzione (Tonica) dà il colore emotivo." },
{ q:"Perché G7 → Am è una cadenza d'inganno?", opts:["Perché G7 è mal risolto","Perché l'orecchio si aspettava C (tonica principale) ma riceve Am — sorpresa armonica","Perché Am non è in C maggiore","Perché G7 non è la dominante"], a:1, fb:"La cadenza d'inganno tradisce le aspettative: G7 (dominante) dovrebbe risolvere su C (tonica). Andando verso Am (tonica sostitutiva), si crea una sorpresa che prolunga la frase." },
{ q:"In G maggiore, la dominante è:", opts:["D","D7","C","A7"], a:1, fb:"In G maggiore, V = D. Con la settima: D7 (Re–Fa#–La–Do). D7 contiene il tritono di G maggiore (C e F#) — si risolve su G." },
{ q:"La progressione Dm–G7–C è analizzata come:", opts:["T–D–SD","SD–D–T","D–T–SD","T–SD–D"], a:1, fb:"Dm = Sottodominante (II), G7 = Dominante (V), C = Tonica (I). SD–D–T è l'incatenamento fondamentale — è la cadenza del II–V–I." },
{ q:"Qual è la differenza funzionale tra G e G7 in C maggiore?", opts:["Nessuna","G7 è più instabile — contiene il tritono completo (F), G non lo contiene","G è più instabile","G7 è una tonica"], a:1, fb:"G (G–B–D) contiene B (sensibile) ma non F. G7 (G–B–D–F) contiene entrambe le note del tritono. G7 è nettamente più teso e si risolve più fortemente verso C." },
{ q:"In D maggiore, quali note formano il tritono (IV e VII grado)?", opts:["D e A","G e C#","F# e B","E e A"], a:1, fb:"In D maggiore, IV = G e VII = C#. G–C# = 6 semitoni = tritono. La dominante di D maggiore è A7, che contiene G e C#." },
{ q:"Una cadenza perfetta è:", opts:["IV → I","V → I con entrambi gli accordi in stato fondamentale","V → VI","II → V"], a:1, fb:"Cadenza perfetta = V → I, entrambi in stato fondamentale. È la cadenza più conclusiva — G7 (fondamentale) → C (fondamentale) in C maggiore." },
{ q:"Una cadenza imperfetta differisce da quella perfetta perché:", opts:["Usa IV invece di V","Almeno uno dei due accordi è rivolto","Si risolve su VI","È in modo minore"], a:1, fb:"Cadenza imperfetta = V → I, ma almeno un accordo è rivolto. La risoluzione è percepibile ma meno ferma rispetto a entrambi gli accordi in stato fondamentale." },
{ q:"Una cadenza plagale è:", opts:["V → I","IV → I — dolce e solenne","II → V","V → VI"], a:1, fb:"Cadenza plagale = IV → I (F → C in C maggiore). Il suo colore dolce e solenne le vale il soprannome di cadenza 'Amen' — molto presente nella musica sacra." },
{ q:"Una semicadenza termina su:", opts:["I","II","IV","V — la frase rimane sospesa"], a:3, fb:"La semicadenza termina sulla dominante (V) senza risolvere. È una sospensione — come una domanda rimasta senza risposta. L'orecchio aspetta il seguito." },
{ q:"La cadenza d'inganno V → VI crea un effetto di:", opts:["Risoluzione forte","Sorpresa — l'orecchio si aspettava I ma riceve VI","Instabilità massima","Conclusione definitiva"], a:1, fb:"La cadenza d'inganno disattende le aspettative — V dovrebbe risolvere su I, ma va su VI. L'effetto sorpresa permette di prolungare la frase senza concludere." },
{ q:"Il ciclo delle quinte discendenti è:", opts:["I–II–III–IV–V–VI–VII","I–IV–VII–III–VI–II–V–I — ogni accordo scende di una quinta","V–IV–III–II–I","I–V–IV–I"], a:1, fb:"I–IV–VII–III–VI–II–V–I: ogni accordo scende di una quinta (o sale di una quarta) rispetto al precedente. Questo movimento di quinta è il più naturale e il più forte dell'armonia." },
{ q:"La tecnica del 'pendolo' consiste in:", opts:["Alternare solo tra dominante e tonica","Alternare tra due funzioni (es: T–SD–T–SD) prima di progredire","Ripetere indefinitamente lo stesso accordo","Cambiare tonalità ad ogni misura"], a:1, fb:"Il pendolo alterna tra due funzioni (spesso T–SD o T–D) creando un effetto di oscillazione. Es: C–Am–F–C–Am–F… prima di una cadenza finale G7–C." },
{ q:"L'estensione di funzione consiste in:", opts:["Ripetere un accordo due volte","Incatenare più accordi della stessa funzione per prolungarla","Cambiare il basso di un accordo","Rivoltare un accordo"], a:1, fb:"Si può prolungare una funzione incatenando più accordi dello stesso ruolo. Es: Dm–F–G7–C = SD–SD–D–T. Le due sottodominanti danno più peso alla preparazione." },
{ q:"Nel ciclo delle quinte in C maggiore, quale accordo segue Dm?", opts:["C","G","Am","Bdim"], a:1, fb:"I–IV–VII–III–VI–II–V–I. Dm è il II grado. Il successivo nel ciclo = V grado = G. Dm → G: la fondamentale scende di una quinta (Re → Sol)." },
{ q:"La progressione ii–V–I (2–5–1) è fondamentale perché:", opts:["Usa tre accordi","SD → D → T in tetrade, con note comuni che ottimizzano la condotta delle voci","È in minore","Usa il tritono due volte"], a:1, fb:"II–V–I = SD–D–T in versione arricchita (tetradi). Le note comuni tra Dm7 e G7 (D e F) permettono una condotta delle voci minimale — è la cadenza più efficiente della musica tonale." },
{ q:"In C maggiore, la progressione Dm7 → G7 ha quante note comuni?", opts:["0","1","2","4"], a:2, fb:"Dm7 = D–F–A–C. G7 = G–B–D–F. Note comuni: D e F (2 note). Queste due note possono rimanere ferme, e solo A–C devono muoversi verso B–G." },
{ q:"Per passare da II a V in un II–V–I minimale, quali voci devono muoversi?", opts:["Tutte le voci","Solo la fondamentale e la terza — le altre due rimangono ferme","Nessuna voce si muove","Tutte tranne il basso"], a:1, fb:"Da Dm7 (D–F–A–C) verso G7 (G–B–D–F): D rimane, F rimane. Solo A scende verso G e C scende verso B. Condotta delle voci minimale — due movimenti congiunti discendenti." },
{ q:"La progressione C–Am–F–G è funzionalmente:", opts:["T–D–SD–D","T–T–SD–D","SD–T–D–T","D–T–SD–T"], a:1, fb:"C = T, Am = T (sostituzione diatonica), F = SD, G = D. T–T–SD–D — è il ciclo armonico di moltissime canzoni pop moderne." },
{ q:"Nella progressione G7 → C, il tritono si risolve per:", opts:["Due movimenti ascendenti","Due movimenti discendenti","Movimento contrario: B sale verso C (+½), F scende verso E (-½)","Due salti di terza"], a:2, fb:"B (terza di G7, sensibile) sale verso C (+½ tono). F (settima di G7) scende verso E (terza di C) (-½ tono). Questo doppio movimento contrario per semitono è la risoluzione del tritono." },
{ q:"Perché la cadenza perfetta richiede entrambi gli accordi in stato fondamentale?", opts:["Per convenzione arbitraria","Le fondamentali V e I al basso creano il segnale acustico più forte di una risoluzione — il basso 'conferma' il movimento armonico","Perché i rivolti sono proibiti","Per facilitare la lettura"], a:1, fb:"Il basso è il fondamento dell'armonia. Quando Sol (V) e Do (I) sono al basso, il cambio di fondamentale è percepito come una risoluzione ferma e definitiva." },
{ q:"Quale cadenza termina tradizionalmente un brano classico?", opts:["Semicadenza","Cadenza plagale","Cadenza perfetta","Cadenza d'inganno"], a:2, fb:"La cadenza perfetta (V–I, stato fondamentale) è la conclusione tradizionale. Porta la risoluzione più ferma e conclusiva — segnale chiaro di fine frase o di brano." },
{ q:"La progressione Am–Dm–G7–C è analizzata come:", opts:["D–T–SD–T","T–SD–D–T","SD–D–T–SD","T–D–SD–T"], a:1, fb:"Am = T (VI), Dm = SD (II), G7 = D (V), C = T (I). T–SD–D–T — è una variazione del ciclo fondamentale. Am come tonica iniziale è frequente nelle progressioni in minore relativo." },
{ q:"In G maggiore, il II–V–I corrisponde a:", opts:["Am–D–G","Am7–D7–GMaj7","Em–D–G","Bm–E7–A"], a:1, fb:"In G maggiore: II = Am7, V = D7, I = GMaj7. La cadenza Am7–D7–GMaj7 è il II–V–I di G maggiore." },
{ q:"Le quattro voci del modello SATB sono:", opts:["Soprano, Tenore, Alto, Baritono","Soprano, Alto, Tenore, Basso","Soprano, Mezzosoprano, Tenore, Basso","Soprano, Alto, Baritono, Basso"], a:1, fb:"SATB = Soprano (voce femminile acuta), Alto (voce femminile grave), Tenore (voce maschile acuta), Basso (voce maschile grave). Ogni voce ha la propria tessitura." },
{ q:"La tessitura del soprano è:", opts:["G3 a C5","C4 a G5","C3 a G4","E2 a C4"], a:1, fb:"Soprano: C4 (Do centrale) a G5. Alto: G3 a C5. Tenore: C3 a G4. Basso: E2 a C4. Queste tessiture garantiscono il comfort vocale e l'equilibrio acustico." },
{ q:"Le quinte parallele sono proibite perché:", opts:["Sono troppo dissonanti","Annullano l'indipendenza delle voci — due voci in quinta parallela suonano come una sola","Creano quinte aumentate","Sono impossibili da cantare"], a:1, fb:"Le quinte parallele danno l'illusione che due voci siano una sola — si 'incollano' insieme e perdono la loro indipendenza melodica. La scrittura polifonica richiede voci indipendenti." },
{ q:"Il movimento contrario tra due voci è:", opts:["Entrambe le voci salgono insieme","Entrambe le voci scendono insieme","Una voce sale, l'altra scende — il movimento più equilibrato","Una voce rimane ferma"], a:2, fb:"Il movimento contrario è il più equilibrato e il più favorevole all'indipendenza delle voci. Evita naturalmente ottave e quinte parallele e dà vitalità alla scrittura." },
{ q:"Il movimento obliquo è:", opts:["Entrambe le voci che salgono","Una voce che rimane ferma mentre l'altra si muove","Entrambe le voci che scendono","Un salto di quinta in entrambe le voci"], a:1, fb:"Il movimento obliquo: una voce tiene una nota (o la ripete) mentre l'altra si muove. Molto frequente durante le risoluzioni, in particolare per la sensibile ascendente." },
{ q:"Perché si preferiscono i movimenti congiunti (seconde)?", opts:["Perché sono più facili da scrivere","Perché sono più naturali vocalmente e riducono i rischi di parallele","Perché creano più tensione","Perché sono obbligatori"], a:1, fb:"I movimenti congiunti (per seconde) sono i più naturali per le voci — cantabili e fluidi. Minimizzano i salti difficili e riducono i rischi di ottave o quinte parallele." },
{ q:"La regola del raddoppio in un accordo in stato fondamentale è:", opts:["Raddoppiare la terza","Raddoppiare la quinta","Raddoppiare la fondamentale (tranne al VII grado)","Raddoppiare la settima"], a:2, fb:"Si raddoppia la fondamentale per impostazione predefinita — è la nota più stabile. Eccezione: al VII grado (Bdim), si raddoppia la terza (D) perché B è la sensibile — non si raddoppia mai la sensibile." },
{ q:"Perché non si raddoppia mai la sensibile?", opts:["Perché è troppo acuta","Perché raddoppiarla crea due risoluzioni obbligatorie verso la stessa nota — problema di ottave parallele alla risoluzione","Perché è troppo grave","Perché è instabile e difficile da intonare"], a:1, fb:"Raddoppiare la sensibile creerebbe due B che devono entrambi salire verso C — producendo ottave parallele alla risoluzione. È una grave mancanza nella scrittura a 4 voci." },
{ q:"La distanza massima consentita tra soprano e alto è:", opts:["Una terza","Una quinta","Un'ottava","Due ottave"], a:2, fb:"Tra soprano–alto e tra alto–tenore: massimo un'ottava. Tra tenore–basso: fino a due ottave tollerate. Queste proporzioni mantengono l'equilibrio dello spettro sonoro." },
{ q:"Un incrocio di voci si verifica quando:", opts:["Due voci suonano la stessa nota","L'alto canta più in alto del soprano (o il tenore più in alto dell'alto, ecc.)","Due voci fanno un salto di quinta","Il basso sale nel registro del tenore"], a:1, fb:"L'incrocio di voci: una voce inferiore supera una voce superiore. Es: l'alto (G3–C5) che sale più in alto del soprano corrente. Vietato nella scrittura rigorosa." },
{ q:"Un sorpasso di voci si verifica quando:", opts:["Due voci suonano la stessa nota","Una voce supera la nota che la voce adiacente ha appena lasciato","Due voci salgono insieme","Il basso è troppo grave"], a:1, fb:"Il sorpasso: una voce 'scavalca' la nota della voce adiacente. Es: l'alto sale più in alto della nota che il soprano aveva appena lasciato. Vietato nella scrittura rigorosa." },
{ q:"Durante il passaggio II → V in un II–V–I, le voci F e C (di Dm7):", opts:["Salgono verso G e D","Scendono: F rimane su F (7a di G7) e C scende verso B (3a di G7)","Saltano di una terza","Rimangono ferme"], a:1, fb:"F rimane su F (la settima di G7). C scende verso B (la terza di G7). È il movimento congiunto minimale: A (5a di Dm7) scende verso G (fondamentale di G7). Solo due movimenti." },
{ q:"La regola 'la settima scende' significa:", opts:["La settima di qualsiasi accordo scende","La settima di dominante (F in G7) deve scendere per grado congiunto (F→E) durante la risoluzione sulla tonica","La settima di un accordo minore scende","La settima di un accordo Maj7 scende"], a:1, fb:"La settima di dominante (F in G7) scende congiuntamente verso la terza dell'accordo di risoluzione (E in C). Regola assoluta nella scrittura armonica." },
{ q:"Nella scrittura a 4 voci, le 'ottave dirette' tra soprano e basso sono:", opts:["Consentite in tutti i casi","Vietate in movimento diretto — tollerate se il soprano avanza per gradi congiunti","Sempre obbligatorie","Consentite solo in minore"], a:1, fb:"Le ottave dirette (soprano e basso che si muovono nella stessa direzione per formare un'ottava) sono generalmente vietate. Unica tolleranza: se il soprano avanza per semitono o tono." },
{ q:"Perché i movimenti disgiunti (grandi intervalli) sono da evitare nelle voci interne?", opts:["Perché creano consonanze","Perché creano rischi di parallele, sono difficili da cantare e rompono la fluidità melodica","Perché sono troppo brevi","Perché creano troppe dissonanze"], a:1, fb:"I grandi salti nelle voci interne (contralto, tenore) rompono la fluidità, sono difficili da intonare e aumentano i rischi di errori (parallele, sorpassi). I grandi intervalli sono riservati al basso." },
];

const questionsPt: Question[] = [{ q:"Quantos tons contém o trítono?", opts:["2","3","4","6"], a:1, fb:"O trítono = 3 tons (6 semitons). Seu nome vem daí — tri-tom. Em C maior, ele se forma entre F e B." },
{ q:"Em C maior, quais notas formam o trítono?", opts:["C e G","F e B","E e A","D e A"], a:1, fb:"F (Fá, IV grau) e B (Si, VII grau) são as duas notas do trítono de C maior. São as notas constitutivas do acorde G7." },
{ q:"Por que o trítono é instável?", opts:["Por ser muito grave","Por estar no meio da oitava — sua ambiguidade acústica cria uma forte tensão em direção à resolução","Por conter sempre bemóis","Por ser raro na música"], a:1, fb:"O trítono divide a oitava em duas partes iguais (6+6 semitons) — é perfeitamente simétrico. Essa ausência de direção cria uma tensão que clama por resolução." },
{ q:"Para quais graus o trítono resolve naturalmente?", opts:["Para V e VII","Para I e III (ou seus equivalentes)","Para II e IV","Para VI e VII"], a:1, fb:"O trítono F–B resolve por semitom conjunto: F desce para E (terça de C) e B sobe para C (tônica). A resolução aponta para os graus I e III." },
{ q:"Em G7, a nota F é:", opts:["A fundamental","A terça","A quinta","A sétima"], a:3, fb:"G7 = G–B–D–F. F é a sétima (menor) de G7. É metade do trítono — deve descer para E na resolução." },
{ q:"Em G7, a nota B é:", opts:["A fundamental","A terça","A quinta","A sétima"], a:1, fb:"G7 = G–B–D–F. B é a terça de G7 — e é a sensível de C maior. Deve subir para C na resolução." },
{ q:"Na resolução G7 → C, a sensível B:", opts:["Desce para G","Sobe para C por semitom","Permanece em B","Salta para E"], a:1, fb:"B (sensível) sobe obrigatoriamente para C (tônica). Esse semitom ascendente é a resolução da sensível — regra absoluta da harmonia tonal." },
{ q:"Na resolução G7 → C, a sétima F:", opts:["Sobe para G","Desce para E por grau conjunto","Permanece em F","Salta para C"], a:1, fb:"F (sétima de dominante) desce para E (terça de C). Esse semitom descendente é a resolução da sétima — regra absoluta." },
{ q:"O trítono de G maior é formado por:", opts:["G e D","C e F#","B e E","A e D"], a:1, fb:"Em G maior, os graus IV (C) e VII (F#) formam o trítono. C–F# = 6 semitons = trítono." },
{ q:"Qual acorde de C maior contém as duas notas do trítono (F e B)?", opts:["C","F","G7","Am"], a:2, fb:"G7 = G–B–D–F. Contém B (sensível) e F (7ª de dominante) — o trítono completo. Por isso G7 é a dominante perfeita." },
{ q:"O trítono é instável há quantos séculos na música ocidental?", opts:["Cerca de 100 anos","Cerca de 400 anos","Cerca de 1.000 anos","Desde sempre"], a:1, fb:"Há cerca de 400 anos (música barroca), o trítono está no centro da tensão harmônica da música tonal. A harmonia funcional repousa sobre essa instabilidade." },
{ q:"A resolução do trítono F–B se dá por:", opts:["Dois movimentos ascendentes","Dois movimentos descendentes","Um movimento ascendente (B→C) e um descendente (F→E) — movimentos contrários","Dois saltos de quinta"], a:2, fb:"B sobe para C (+½ tom) e F desce para E (-½ tom). Esse duplo movimento contrário por semitom é a resolução do trítono — muito estável por ser simétrico." },
{ q:"O acorde Bdim contém o trítono de C maior?", opts:["Não","Sim — contém B e F, as duas notas do trítono","Contém F mas não B","Contém B mas não F"], a:1, fb:"Bdim = B–D–F. Contém B (sensível) e F (subdominante) — o trítono completo. Por isso Bdim é uma alternativa funcional a G7: ambos são dominante." },
{ q:"O trítono também é chamado de:", opts:["Quarta diminuta","Quinta diminuta ou quarta aumentada","Sexta menor","Sétima diminuta"], a:1, fb:"O trítono = quarta aumentada (F–B ascendente) ou quinta diminuta (B–F descendente). 6 semitons nos dois casos — mesmo intervalo, nomes diferentes conforme o sentido." },
{ q:"Em F maior, quais notas formam o trítono?", opts:["F e C","Bb e E","G e D","A e Eb"], a:1, fb:"Em F maior, IV = Bb e VII = E. O trítono de F maior é Bb–E (6 semitons). O acorde de dominante de F é C7, que contém Bb e E." },
{ q:"Por que o trítono é a chave da harmonia funcional?", opts:["Por ser raro","Porque sua presença ou ausência define as funções T, SD e D — ele organiza toda a tensão harmônica","Por criar acordes de 4 notas","Por pertencer somente à escala menor"], a:1, fb:"A presença das duas notas do trítono → Dominante. Apenas uma → Subdominante. Nenhuma → Tônica. O trítono é o 'termostato' da tensão harmônica." },
{ q:"Quantas funções tonais principais existem?", opts:["2","3","4","5"], a:1, fb:"Três funções: Tônica (T), Subdominante (SD), Dominante (D). Elas organizam todos os acordes segundo seu papel na tensão/resolução." },
{ q:"A função Tônica é caracterizada por:", opts:["A presença do trítono completo","A ausência de F e B — estabilidade, resolução, repouso","A presença de F sozinho","A presença de B sozinho"], a:1, fb:"A Tônica não contém nenhuma das duas notas do trítono (nem F nem B). É estável — é o ponto de repouso e resolução. Em C: I (C) e VI (Am)." },
{ q:"A função Subdominante é caracterizada por:", opts:["A presença do trítono completo","A presença de F (IV grau) mas não de B","A presença de B mas não de F","A ausência de F e B"], a:1, fb:"A Subdominante contém F (subdominante) mas não B (sensível). Ela prepara a tensão sem ser seu ápice. Em C: II (Dm) e IV (F)." },
{ q:"A função Dominante é caracterizada por:", opts:["A ausência de trítono","A presença de F sozinho","A presença do trítono completo (F e B)","A presença de B sozinho"], a:2, fb:"A Dominante contém as duas notas do trítono (F e B). É o ápice da tensão — clama imperativamente pela resolução na Tônica. Em C: V (G7) e VII (Bdim)." },
{ q:"Em C maior, quais acordes têm a função Tônica?", opts:["C e G","Dm e F","C e Am","G7 e Bdim"], a:2, fb:"C (I) e Am (VI): nenhum contém F nem B. São as duas tônicas de C maior. Am é uma tônica 'suave', frequentemente usada nas cadências deceptivas." },
{ q:"Em C maior, quais acordes têm a função Dominante?", opts:["G7 e Am","G7 e Bdim","C e Em","Dm e F"], a:1, fb:"G7 (V) e Bdim (VII) contêm ambos F e B — o trítono completo. São as duas dominantes de C maior." },
{ q:"Em C maior, quais acordes têm a função Subdominante?", opts:["C e Am","G7 e Bdim","Dm e F","Em e G"], a:2, fb:"Dm (II) e F (IV) contêm F mas não B. São as duas subdominantes de C maior." },
{ q:"O encadeamento fundamental da harmonia tonal é:", opts:["T → D → SD","SD → D → T","D → T → SD","T → SD → T"], a:1, fb:"SD → D → T é a 'espinha dorsal' da harmonia tonal. A Subdominante prepara a Dominante, que resolve na Tônica." },
{ q:"O que é uma substituição diatônica?", opts:["Um acorde invertido","Substituir um acorde por outro de mesma função na mesma tonalidade","Um acorde emprestado de outra tonalidade","Um acorde de 4 sons"], a:1, fb:"Uma substituição diatônica substitui um acorde por outro de mesma função na mesma tonalidade. Ex: Am pode substituir C (ambos = Tônica em C)." },
{ q:"Em C maior, Dm pode substituir F porque:", opts:["Têm a mesma fundamental","Ambos têm a função Subdominante — contêm F mas não B","Têm as mesmas notas","Estão à quinta um do outro"], a:1, fb:"Dm (II) e F (IV) têm ambos a função Subdominante: contêm F (IV grau) mas não B. Podem, portanto, substituir-se sem alterar a lógica funcional." },
{ q:"Em C maior, Am pode substituir C porque:", opts:["Am é mais grave","Ambos têm a função Tônica — nem F nem B","Am é mais estável","Têm a mesma fundamental"], a:1, fb:"Am (VI) e C (I) têm ambos a função Tônica. A cadência deceptiva (G7 → Am em vez de G7 → C) explora essa substituição para criar efeito de surpresa." },
{ q:"Por que Em é considerado um acorde 'bastardo'?", opts:["Por ser diminuto","Por conter apenas B (a sensível) sem F — sua função é ambígua e raramente é usado sozinho","Por ser muito agudo","Por não pertencer a C maior"], a:1, fb:"Em (III) contém B (sensível de C) mas não F (subdominante). Não se enquadra claramente em nenhuma das três funções. Os compositores divergem sobre seu papel." },
{ q:"A progressão I–VI–II–V–I em C é:", opts:["T–D–SD–D–T","T–T–SD–D–T","SD–D–T–D–T","T–D–T–SD–T"], a:1, fb:"C(T) – Am(T) – Dm(SD) – G(D) – C(T) = T–T–SD–D–T. As duas tônicas se encadeiam (I e VI), depois segue o ciclo SD–D–T." },
{ q:"Por que encadear apenas tônicas é entediante?", opts:["Porque as tônicas são dissonantes","Porque a música fica estável demais sem tensão — não há movimento","Porque as tônicas são instáveis","Porque não se pode cantar sobre elas"], a:1, fb:"A música funciona pelo contraste entre tensão e resolução. Apenas tônicas = estabilidade excessiva, sem impulso. Apenas dominantes = desconforto excessivo. O equilíbrio é essencial." },
{ q:"A 'cor emocional' de uma progressão é determinada por:", opts:["Seu andamento","A resolução — o acorde de tônica e sua cor maior ou menor","O número de acordes","A altura das notas"], a:1, fb:"Na harmonia funcional, a emoção vem da resolução — que cor chega à tônica. A tensão (Dominante) cria a expectativa, a resolução (Tônica) dá a cor emocional." },
{ q:"Por que G7 → Am é uma cadência deceptiva?", opts:["Porque G7 está mal resolvido","Porque o ouvido esperava C (tônica principal) mas recebe Am — surpresa harmônica","Porque Am não está em C maior","Porque G7 não é a dominante"], a:1, fb:"A cadência deceptiva engana as expectativas: G7 (dominante) deveria resolver em C (tônica). Indo para Am (tônica substituta), cria-se uma surpresa que prolonga a frase." },
{ q:"Em G maior, a dominante é:", opts:["D","D7","C","A7"], a:1, fb:"Em G maior, V = D. Com a sétima: D7 (Ré–Fá#–Lá–Dó). D7 contém o trítono de G maior (C e F#) — resolve em G." },
{ q:"A progressão Dm–G7–C é analisada como:", opts:["T–D–SD","SD–D–T","D–T–SD","T–SD–D"], a:1, fb:"Dm = Subdominante (II), G7 = Dominante (V), C = Tônica (I). SD–D–T é o encadeamento fundamental — é a cadência do II–V–I." },
{ q:"Qual é a diferença funcional entre G e G7 em C maior?", opts:["Nenhuma","G7 é mais instável — contém o trítono completo (F), G não o contém","G é mais instável","G7 é uma tônica"], a:1, fb:"G (G–B–D) contém B (sensível) mas não F. G7 (G–B–D–F) contém as duas notas do trítono. G7 é nitidamente mais tenso e resolve com mais força em C." },
{ q:"Em D maior, quais notas formam o trítono (IV e VII graus)?", opts:["D e A","G e C#","F# e B","E e A"], a:1, fb:"Em D maior, IV = G e VII = C#. G–C# = 6 semitons = trítono. A dominante de D maior é A7, que contém G e C#." },
{ q:"Uma cadência perfeita é:", opts:["IV → I","V → I com os dois acordes no estado fundamental","V → VI","II → V"], a:1, fb:"Cadência perfeita = V → I, ambos no estado fundamental. É a cadência mais conclusiva — G7 (fundamental) → C (fundamental) em C maior." },
{ q:"Uma cadência imperfeita difere da perfeita porque:", opts:["Usa IV em vez de V","Pelo menos um dos dois acordes está invertido","Resolve em VI","Está em modo menor"], a:1, fb:"Cadência imperfeita = V → I, mas pelo menos um acorde está invertido. A resolução é perceptível, porém menos firme do que com os dois acordes no estado fundamental." },
{ q:"Uma cadência plagal é:", opts:["V → I","IV → I — suave e solene","II → V","V → VI"], a:1, fb:"Cadência plagal = IV → I (F → C em C maior). Sua cor suave e solene lhe valeu o apelido de cadência 'Amém' — muito presente na música sacra." },
{ q:"Uma semicadência termina em:", opts:["I","II","IV","V — a frase fica suspensa"], a:3, fb:"A semicadência termina na dominante (V) sem resolver. É uma suspensão — como uma pergunta sem resposta. O ouvido aguarda a continuação." },
{ q:"A cadência deceptiva V → VI cria um efeito de:", opts:["Resolução forte","Surpresa — o ouvido esperava I mas recebe VI","Instabilidade máxima","Conclusão definitiva"], a:1, fb:"A cadência deceptiva frustra as expectativas — V deveria resolver em I, mas vai para VI. O efeito de surpresa permite prolongar a frase sem concluir." },
{ q:"O ciclo das quintas descendentes é:", opts:["I–II–III–IV–V–VI–VII","I–IV–VII–III–VI–II–V–I — cada acorde desce uma quinta","V–IV–III–II–I","I–V–IV–I"], a:1, fb:"I–IV–VII–III–VI–II–V–I: cada acorde desce uma quinta (ou sobe uma quarta) em relação ao anterior. Esse movimento de quinta é o mais natural e poderoso da harmonia." },
{ q:"A técnica do 'pêndulo' consiste em:", opts:["Alternar apenas entre dominante e tônica","Alternar entre duas funções (ex: T–SD–T–SD) antes de progredir","Repetir indefinidamente o mesmo acorde","Mudar de tonalidade a cada compasso"], a:1, fb:"O pêndulo alterna entre duas funções (frequentemente T–SD ou T–D), criando um efeito de oscilação. Ex: C–Am–F–C–Am–F… antes de uma cadência final G7–C." },
{ q:"A extensão de função consiste em:", opts:["Repetir um acorde duas vezes","Encadear vários acordes de mesma função para prolongá-la","Mudar o baixo de um acorde","Inverter um acorde"], a:1, fb:"Pode-se prolongar uma função encadeando vários acordes do mesmo papel. Ex: Dm–F–G7–C = SD–SD–D–T. As duas subdominantes dão mais peso à preparação." },
{ q:"No ciclo das quintas em C maior, qual acorde segue Dm?", opts:["C","G","Am","Bdim"], a:1, fb:"I–IV–VII–III–VI–II–V–I. Dm é o II grau. O seguinte no ciclo = V grau = G. Dm → G: a fundamental desce uma quinta (Ré → Sol)." },
{ q:"A progressão ii–V–I (2–5–1) é fundamental porque:", opts:["Usa três acordes","SD → D → T em tétrades, com notas comuns que otimizam a condução de vozes","Está em modo menor","Usa o trítono duas vezes"], a:1, fb:"II–V–I = SD–D–T em versão enriquecida (tétrades). As notas comuns entre Dm7 e G7 (D e F) permitem condução de voz mínima — é a cadência mais eficiente da música tonal." },
{ q:"Em C maior, a progressão Dm7 → G7 usa quantas notas em comum?", opts:["0","1","2","4"], a:2, fb:"Dm7 = D–F–A–C. G7 = G–B–D–F. Notas comuns: D e F (2 notas). Essas duas notas podem permanecer no lugar, e apenas A–C precisam se mover para B–G." },
{ q:"Para passar de II a V num II–V–I mínimo, quais vozes precisam se mover?", opts:["Todas as vozes","Apenas a fundamental e a terça — as outras duas ficam no lugar","Nenhuma voz se move","Todas exceto o baixo"], a:1, fb:"De Dm7 (D–F–A–C) para G7 (G–B–D–F): D permanece, F permanece. Apenas A desce para G e C desce para B. Condução de voz mínima — dois movimentos conjuntos descendentes." },
{ q:"A progressão C–Am–F–G é funcionalmente:", opts:["T–D–SD–D","T–T–SD–D","SD–T–D–T","D–T–SD–T"], a:1, fb:"C = T, Am = T (substituição diatônica), F = SD, G = D. T–T–SD–D — é o ciclo harmônico de muitas canções pop modernas." },
{ q:"Na progressão G7 → C, o trítono resolve por:", opts:["Dois movimentos ascendentes","Dois movimentos descendentes","Movimento contrário: B sobe para C (+½), F desce para E (-½)","Dois saltos de terça"], a:2, fb:"B (terça de G7, sensível) sobe para C (+½ tom). F (sétima de G7) desce para E (terça de C) (-½ tom). Esse duplo movimento contrário por semitom é a resolução do trítono." },
{ q:"Por que a cadência perfeita exige os dois acordes no estado fundamental?", opts:["Por convenção arbitrária","As fundamentais V e I no baixo criam o sinal acústico mais forte de uma resolução — o baixo 'confirma' o movimento harmônico","Porque as inversões são proibidas","Para facilitar a leitura"], a:1, fb:"O baixo é o alicerce da harmonia. Quando Sol (V) e Dó (I) estão no baixo, a mudança de fundamental é percebida como uma resolução firme e definitiva." },
{ q:"Qual cadência tradicionalmente encerra uma peça clássica?", opts:["Semicadência","Cadência plagal","Cadência perfeita","Cadência deceptiva"], a:2, fb:"A cadência perfeita (V–I, estado fundamental) é a conclusão tradicional. Traz a resolução mais firme e conclusiva — sinal claro de fim de frase ou de peça." },
{ q:"A progressão Am–Dm–G7–C é analisada como:", opts:["D–T–SD–T","T–SD–D–T","SD–D–T–SD","T–D–SD–T"], a:1, fb:"Am = T (VI), Dm = SD (II), G7 = D (V), C = T (I). T–SD–D–T — é uma variação do ciclo fundamental. Am como tônica inicial é frequente em progressões no relativo menor." },
{ q:"Em G maior, o II–V–I corresponde a:", opts:["Am–D–G","Am7–D7–GMaj7","Em–D–G","Bm–E7–A"], a:1, fb:"Em G maior: II = Am7, V = D7, I = GMaj7. A cadência Am7–D7–GMaj7 é o II–V–I de G maior." },
{ q:"As quatro vozes do modelo SATB são:", opts:["Soprano, Tenor, Contralto, Barítono","Soprano, Contralto, Tenor, Baixo","Soprano, Mezzo-soprano, Tenor, Baixo","Soprano, Contralto, Barítono, Baixo"], a:1, fb:"SATB = Soprano (voz feminina aguda), Contralto (voz feminina grave), Tenor (voz masculina aguda), Baixo (voz masculina grave). Cada voz tem sua própria tessitura." },
{ q:"A tessitura do soprano é:", opts:["G3 a C5","C4 a G5","C3 a G4","E2 a C4"], a:1, fb:"Soprano: C4 (Dó central) a G5. Contralto: G3 a C5. Tenor: C3 a G4. Baixo: E2 a C4. Essas tessituras garantem o conforto vocal e o equilíbrio acústico." },
{ q:"As quintas paralelas são proibidas porque:", opts:["São demasiado dissonantes","Anulam a independência das vozes — duas vozes em quinta paralela soam como uma só","Criam quintas aumentadas","São impossíveis de cantar"], a:1, fb:"As quintas paralelas dão a ilusão de que duas vozes são uma só — elas 'colam' juntas e perdem sua independência melódica. A escrita polifônica exige vozes independentes." },
{ q:"O movimento contrário entre duas vozes é:", opts:["As duas vozes sobem juntas","As duas vozes descem juntas","Uma voz sobe, a outra desce — o movimento mais equilibrado","Uma voz permanece imóvel"], a:2, fb:"O movimento contrário é o mais equilibrado e o mais favorável à independência das vozes. Evita naturalmente as oitavas e quintas paralelas e dá vitalidade à escrita." },
{ q:"O movimento oblíquo é:", opts:["As duas vozes que sobem","Uma voz que permanece imóvel enquanto a outra se move","As duas vozes que descem","Um salto de quinta nas duas vozes"], a:1, fb:"O movimento oblíquo: uma voz sustenta uma nota (ou a repete) enquanto a outra se move. Muito frequente nas resoluções, especialmente para a sensível ascendente." },
{ q:"Por que se privilegiam os movimentos conjuntos (segundas)?", opts:["Por serem mais fáceis de escrever","Por serem mais naturais vocalmente e reduzirem os riscos de paralelas","Por criarem mais tensão","Por serem obrigatórios"], a:1, fb:"Os movimentos conjuntos (por segundas) são os mais naturais para as vozes — cantáveis e fluidos. Minimizam os saltos difíceis e reduzem os riscos de oitavas ou quintas paralelas." },
{ q:"A regra do dobramento num acorde no estado fundamental é:", opts:["Dobrar a terça","Dobrar a quinta","Dobrar a fundamental (exceto no VII grau)","Dobrar a sétima"], a:2, fb:"Dobra-se a fundamental por padrão — é a nota mais estável. Exceção: no VII grau (Bdim), dobra-se a terça (D), pois B é a sensível — jamais se dobra a sensível." },
{ q:"Por que nunca se dobra a sensível?", opts:["Por ser muito aguda","Porque dobrá-la cria duas resoluções obrigatórias para a mesma nota — problema de oitavas paralelas na resolução","Por ser muito grave","Por ser instável e difícil de entoar"], a:1, fb:"Dobrar a sensível criaria dois B que devem ambos subir para C — produzindo oitavas paralelas na resolução. É uma falta grave na escrita a 4 vozes." },
{ q:"O espaçamento máximo permitido entre soprano e contralto é:", opts:["Uma terça","Uma quinta","Uma oitava","Duas oitavas"], a:2, fb:"Entre soprano–contralto e entre contralto–tenor: máximo de uma oitava. Entre tenor–baixo: até duas oitavas toleradas. Essas proporções mantêm o equilíbrio do espectro sonoro." },
{ q:"Um cruzamento de vozes ocorre quando:", opts:["Duas vozes tocam a mesma nota","O contralto canta mais agudo que o soprano (ou o tenor mais agudo que o contralto, etc.)","Duas vozes fazem um salto de quinta","O baixo sobe para o registro do tenor"], a:1, fb:"O cruzamento de vozes: uma voz inferior ultrapassa uma voz superior. Ex: o contralto (G3–C5) que sobe mais alto que o soprano atual. Proibido na escrita estrita." },
{ q:"Uma sobreposição de vozes ocorre quando:", opts:["Duas vozes tocam a mesma nota","Uma voz ultrapassa a nota que a voz adjacente acabou de deixar","Duas vozes sobem juntas","O baixo está muito grave"], a:1, fb:"A sobreposição: uma voz 'cobre' a nota da voz adjacente. Ex: o contralto sobe mais alto que a nota que o soprano acabava de deixar. Proibido na escrita estrita." },
{ q:"Na passagem II → V num II–V–I, as vozes F e C (de Dm7):", opts:["Sobem para G e D","Descem: F permanece em F (7ª de G7) e C desce para B (3ª de G7)","Saltam uma terça","Ficam imóveis"], a:1, fb:"F permanece em F (a sétima de G7). C desce para B (a terça de G7). É o movimento conjunto mínimo: A (5ª de Dm7) desce para G (fundamental de G7). Apenas dois movimentos." },
{ q:"A regra 'a sétima desce' significa:", opts:["A sétima de todo acorde desce","A sétima de dominante (F em G7) deve descer por grau conjunto (F→E) na resolução sobre a tônica","A sétima de um acorde menor desce","A sétima de um acorde Maj7 desce"], a:1, fb:"A sétima de dominante (F em G7) desce conjuntamente para a terça do acorde de resolução (E em C). Regra absoluta na escrita harmônica." },
{ q:"Na escrita a 4 vozes, as 'oitavas diretas' entre soprano e baixo são:", opts:["Permitidas em todos os casos","Proibidas em movimento direto — toleradas se o soprano avança por graus conjuntos","Sempre obrigatórias","Permitidas apenas em modo menor"], a:1, fb:"As oitavas diretas (soprano e baixo movendo-se na mesma direção para formar uma oitava) são geralmente proibidas. Tolerância única: se o soprano avança por semitom ou tom." },
{ q:"Por que os movimentos disjuntos (grandes intervalos) devem ser evitados nas vozes internas?", opts:["Por criarem consonâncias","Por criarem riscos de paralelas, serem difíceis de cantar e romperem a fluidez melódica","Por serem muito curtos","Por criarem dissonâncias excessivas"], a:1, fb:"Os saltos grandes nas vozes internas (contralto, tenor) rompem a fluidez, são difíceis de entoar e aumentam os riscos de erros (paralelas, sobreposições). Reservam-se os grandes intervalos para o baixo." },
{ q:"A segunda aumentada é:", opts:["Um intervalo diatônico normal","Um intervalo a evitar nas vozes — difícil de cantar e soa 'oriental'","Um intervalo básico em C maior","Um salto de terça"], a:1, fb:"A segunda aumentada (1,5 tom, ex: Ab–B) é difícil de entoar e de cantar. Aparece naturalmente na escala menor harmônica e deve ser evitada nas vozes melódicas." },
{ q:"O que é uma voz 'cantável'?", opts:["Uma voz muito rápida","Uma voz que progride por movimentos conjuntos, permanece na tessitura e não tem saltos difíceis","Uma voz com muitas notas","Uma voz que dobra o soprano"], a:1, fb:"Uma voz cantável: movimentos conjuntos preferidos, tessitura respeitada, saltos limitados, resoluções lógicas. A escrita SATB deve ser vocalmente natural para cada uma das 4 vozes." },
];

